    // ============================================
    // FILE: api/webhooks/stripe.js
    // Stripe webhook handler for subscription management
    // ============================================

    import Stripe from 'stripe';
    import { createClient } from '@supabase/supabase-js';

    const stripe = new Stripe(process.env.STRIPE_SECRET_KEY);
    const supabase = createClient(
      process.env.SUPABASE_URL,
      process.env.SUPABASE_SERVICE_KEY
    );

    export const config = {
      api: {
        bodyParser: false, // Stripe needs raw body
      },
    };

    export default async function handler(req, res) {
      if (req.method !== 'POST') {
        return res.status(405).json({ error: 'Method not allowed' });
      }

      const sig = req.headers['stripe-signature'];
      let event;

      try {
        const rawBody = await buffer(req);
        event = stripe.webhooks.constructEvent(
          rawBody,
          sig,
          process.env.STRIPE_WEBHOOK_SECRET
        );
      } catch (err) {
        console.error(`Webhook signature verification failed: ${err.message}`);
        return res.status(400).send(`Webhook Error: ${err.message}`);
      }

      try {
        switch (event.type) {
          case 'customer.subscription.created':
          case 'customer.subscription.updated':
            await handleSubscriptionChange(event.data.object);
            break;

          case 'customer.subscription.deleted':
            await handleSubscriptionCancellation(event.data.object);
            break;

          case 'invoice.payment_succeeded':
            await resetMonthlyUsage(event.data.object.customer);
            break;

          case 'invoice.payment_failed':
            await handlePaymentFailure(event.data.object);
            break;
        }

        res.json({ received: true });
      } catch (err) {
        console.error(`Webhook handler error: ${err.message}`);
        res.status(500).json({ error: 'Webhook handler failed' });
      }
    }

    async function handleSubscriptionChange(subscription) {
      const customerId = subscription.customer;
      const priceId = subscription.items.data[0].price.id;

      const tierMap = {
        [process.env.STRIPE_PRICE_PROFESSIONAL]: {
          tier: 'professional',
          limit: 1000
        },
        [process.env.STRIPE_PRICE_ENTERPRISE]: {
          tier: 'enterprise',
          limit: 999999 // Effectively unlimited
        }
      };

      const tierInfo = tierMap[priceId] || { tier: 'free', limit: 50 };

      await supabase
        .from('users')
        .update({
          tier: tierInfo.tier,
          stripe_customer_id: customerId,
          subscription_status: subscription.status,
          monthly_operation_limit: tierInfo.limit,
          current_period_end: new Date(subscription.current_period_end * 1000),
          updated_at: new Date()
        })
        .eq('stripe_customer_id', customerId);
    }

    async function handleSubscriptionCancellation(subscription) {
      await supabase
        .from('users')
        .update({
          tier: 'free',
          subscription_status: 'cancelled',
          monthly_operation_limit: 50,
          current_period_end: new Date(subscription.current_period_end * 1000),
          updated_at: new Date()
        })
        .eq('stripe_customer_id', subscription.customer);
    }

    async function resetMonthlyUsage(customerId) {
      await supabase
        .from('users')
        .update({
          operations_used_this_month: 0,
          updated_at: new Date()
        })
        .eq('stripe_customer_id', customerId);
    }

    async function handlePaymentFailure(invoice) {
      // Send email notification
      const { data: user } = await supabase
        .from('users')
        .select('email')
        .eq('stripe_customer_id', invoice.customer)
        .single();

      if (user) {
        // TODO: Integrate email service (SendGrid/Resend)
        console.log(`Payment failed for ${user.email}`);
      }
    }

    function buffer(req) {
      return new Promise((resolve, reject) => {
        const chunks = [];
        req.on('data', (chunk) => chunks.push(chunk));
        req.on('end', () => resolve(Buffer.concat(chunks)));
        req.on('error', reject);
      });
    }


    // ============================================
    // FILE: api/route-task.js
    // Main task routing and execution endpoint
    // ============================================

    import { createClient } from '@supabase/supabase-js';
    import OpenAI from 'openai';
    import Anthropic from '@anthropic-ai/sdk';
    import { GoogleGenerativeAI } from '@google/generative-ai';

    const supabase = createClient(
      process.env.SUPABASE_URL,
      process.env.SUPABASE_ANON_KEY
    );

    const openai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY });
    const anthropic = new Anthropic({ apiKey: process.env.ANTHROPIC_API_KEY });
    const gemini = new GoogleGenerativeAI(process.env.GOOGLE_AI_API_KEY);

    export default async function handler(req, res) {
      if (req.method !== 'POST') {
        return res.status(405).json({ error: 'Method not allowed' });
      }

      const { task, userId } = req.body;

      if (!task || !userId) {
        return res.status(400).json({ error: 'Missing task or userId' });
      }

      try {
        // Check usage limits
        await enforceUsageLimit(userId);

        // Determine optimal model
        const model = determineOptimalModel(task);

        // Create operation record
        const { data: operation } = await supabase
          .from('routing_operations')
          .insert({
            user_id: userId,
            task_description: task,
            routed_to_model: model,
            status: 'processing'
          })
          .select()
          .single();

        // Execute task on selected model
        const result = await executeOnModel(model, task);

        // Calculate coherence score
        const coherence = calculateCoherence(task, result);

        // Update operation with results
        await supabase
          .from('routing_operations')
          .update({
            status: 'complete',
            output: result,
            confidence_score: coherence
          })
          .eq('id', operation.id);

        // Log coherence metrics
        await supabase
          .from('coherence_logs')
          .insert({
            operation_id: operation.id,
            coherence_metrics: { score: coherence, method: 'semantic_similarity' },
            validation_passed: coherence > 0.7
          });

        res.json({
          operationId: operation.id,
          model,
          output: result,
          coherence,
          operationsRemaining: await getRemainingOperations(userId)
        });

      } catch (error) {
        console.error('Task routing error:', error);
        res.status(500).json({ error: error.message });
      }
    }

    async function enforceUsageLimit(userId) {
      const { data: user } = await supabase
        .from('users')
        .select('operations_used_this_month, monthly_operation_limit')
        .eq('id', userId)
        .single();

      if (user.operations_used_this_month >= user.monthly_operation_limit) {
        throw new Error('Monthly operation limit exceeded. Upgrade your plan.');
      }

      await supabase.rpc('increment_operations', { user_id: userId });
    }

    function determineOptimalModel(task) {
      const taskLower = task.toLowerCase();

      // Analytical/Data tasks → DeepSeek (when available) or GPT
      if (taskLower.match(/analy|data|trend|metric|financ|statistic/)) {
        return 'gpt'; // Can swap to DeepSeek when API available
      }

      // Empathetic/Communication tasks → Claude
      if (taskLower.match(/empathy|emotion|communication|letter|apolog|relationship/)) {
        return 'claude';
      }

      // Strategic/Planning tasks → GPT
      if (taskLower.match(/strateg|plan|framework|roadmap|priorit/)) {
        return 'gpt';
      }

      // Creative/Ideation → Gemini
      if (taskLower.match(/creat|ideate|brainstorm|innovate|design/)) {
        return 'gemini';
      }

      // Default to GPT for general tasks
      return 'gpt';
    }

    async function executeOnModel(model, task) {
      switch (model) {
        case 'gpt':
          const gptResponse = await openai.chat.completions.create({
            model: 'gpt-4-turbo-preview',
            messages: [{ role: 'user', content: task }],
            max_tokens: 1000
          });
          return gptResponse.choices[0].message.content;

        case 'claude':
          const claudeResponse = await anthropic.messages.create({
            model: 'claude-3-5-sonnet-20241022',
            max_tokens: 1000,
            messages: [{ role: 'user', content: task }]
          });
          return claudeResponse.content[0].text;

        case 'gemini':
          const geminiModel = gemini.getGenerativeModel({ model: 'gemini-pro' });
          const geminiResponse = await geminiModel.generateContent(task);
          return geminiResponse.response.text();

        default:
          throw new Error(`Unknown model: ${model}`);
      }
    }

    function calculateCoherence(task, output) {
      // Simple coherence calculation based on output length and completeness
      // TODO: Implement proper semantic similarity scoring

      const hasSubstantiveOutput = output.length > 100;
      const appearsComplete = !output.endsWith('...');
      const relevanceKeywords = task.toLowerCase().split(' ')
        .filter(word => word.length > 4)
        .some(keyword => output.toLowerCase().includes(keyword));

      let score = 0.5; // Base score
      if (hasSubstantiveOutput) score += 0.2;
      if (appearsComplete) score += 0.15;
      if (relevanceKeywords) score += 0.15;

      return Math.min(score, 1.0);
    }

    async function getRemainingOperations(userId) {
      const { data: user } = await supabase
        .from('users')
        .select('operations_used_this_month, monthly_operation_limit')
        .eq('id', userId)
        .single();

      return user.monthly_operation_limit - user.operations_used_this_month;
    }


    // ============================================
    // FILE: api/create-checkout.js
    // Stripe checkout session creation
    // ============================================

    import Stripe from 'stripe';

    const stripe = new Stripe(process.env.STRIPE_SECRET_KEY);

    export default async function handler(req, res) {
      if (req.method !== 'POST') {
        return res.status(405).json({ error: 'Method not allowed' });
      }

      const { priceId, userEmail, userId } = req.body;

      try {
        const session = await stripe.checkout.sessions.create({
          customer_email: userEmail,
          client_reference_id: userId,
          payment_method_types: ['card'],
          mode: 'subscription',
          line_items: [
            {
              price: priceId,
              quantity: 1,
            },
          ],
          success_url: `${process.env.NEXT_PUBLIC_URL}/dashboard?session_id={CHECKOUT_SESSION_ID}`,
          cancel_url: `${process.env.NEXT_PUBLIC_URL}/pricing`,
          metadata: {
            userId: userId
          }
        });

        res.json({ sessionId: session.id, url: session.url });
      } catch (error) {
        console.error('Checkout error:', error);
        res.status(500).json({ error: error.message });
      }
    }

