import { eq } from "drizzle-orm";
import { envelopes, envelopeMerges, auditTrail, subscriptions, Envelope, InsertEnvelope, EnvelopeMerge, InsertEnvelopeMerge, AuditEntry, InsertAuditEntry, Subscription, InsertSubscription } from "../drizzle/schema";
import { drizzle } from "drizzle-orm/mysql2";
import { InsertUser, users } from "../drizzle/schema";
import { ENV } from './_core/env';

let _db: ReturnType<typeof drizzle> | null = null;

// Lazily create the drizzle instance so local tooling can run without a DB.
export async function getDb() {
  if (!_db && process.env.DATABASE_URL) {
    try {
      _db = drizzle(process.env.DATABASE_URL);
    } catch (error) {
      console.warn("[Database] Failed to connect:", error);
      _db = null;
    }
  }
  return _db;
}

export async function upsertUser(user: InsertUser): Promise<void> {
  if (!user.openId) {
    throw new Error("User openId is required for upsert");
  }

  const db = await getDb();
  if (!db) {
    console.warn("[Database] Cannot upsert user: database not available");
    return;
  }

  try {
    const values: InsertUser = {
      openId: user.openId,
    };
    const updateSet: Record<string, unknown> = {};

    const textFields = ["name", "email", "loginMethod"] as const;
    type TextField = (typeof textFields)[number];

    const assignNullable = (field: TextField) => {
      const value = user[field];
      if (value === undefined) return;
      const normalized = value ?? null;
      values[field] = normalized;
      updateSet[field] = normalized;
    };

    textFields.forEach(assignNullable);

    if (user.lastSignedIn !== undefined) {
      values.lastSignedIn = user.lastSignedIn;
      updateSet.lastSignedIn = user.lastSignedIn;
    }
    if (user.role !== undefined) {
      values.role = user.role;
      updateSet.role = user.role;
    } else if (user.openId === ENV.ownerOpenId) {
      values.role = 'admin';
      updateSet.role = 'admin';
    }

    if (!values.lastSignedIn) {
      values.lastSignedIn = new Date();
    }

    if (Object.keys(updateSet).length === 0) {
      updateSet.lastSignedIn = new Date();
    }

    await db.insert(users).values(values).onDuplicateKeyUpdate({
      set: updateSet,
    });
  } catch (error) {
    console.error("[Database] Failed to upsert user:", error);
    throw error;
  }
}

export async function getUserByOpenId(openId: string) {
  const db = await getDb();
  if (!db) {
    console.warn("[Database] Cannot get user: database not available");
    return undefined;
  }

  const result = await db.select().from(users).where(eq(users.openId, openId)).limit(1);

  return result.length > 0 ? result[0] : undefined;
}

/**
 * Envelope Operations
 */
export async function createEnvelope(envelope: InsertEnvelope) {
  const db = await getDb();
  if (!db) throw new Error('Database not available');
  return db.insert(envelopes).values(envelope);
}

export async function getEnvelopesByUser(userId: number) {
  const db = await getDb();
  if (!db) throw new Error('Database not available');
  return db.select().from(envelopes).where(eq(envelopes.userId, userId));
}

export async function getEnvelopeById(id: string) {
  const db = await getDb();
  if (!db) throw new Error('Database not available');
  return db.select().from(envelopes).where(eq(envelopes.id, id)).limit(1);
}

/**
 * Merge Operations
 */
export async function createMerge(merge: InsertEnvelopeMerge) {
  const db = await getDb();
  if (!db) throw new Error('Database not available');
  return db.insert(envelopeMerges).values(merge);
}

export async function getMergesByUser(userId: number) {
  const db = await getDb();
  if (!db) throw new Error('Database not available');
  return db.select().from(envelopeMerges).where(eq(envelopeMerges.userId, userId));
}

/**
 * Audit Trail Operations
 */
export async function logAuditEntry(entry: InsertAuditEntry) {
  const db = await getDb();
  if (!db) throw new Error('Database not available');
  return db.insert(auditTrail).values(entry);
}

export async function getAuditTrail(userId: number, limit = 50) {
  const db = await getDb();
  if (!db) throw new Error('Database not available');
  return db.select().from(auditTrail).where(eq(auditTrail.userId, userId)).limit(limit);
}

/**
 * Subscription Operations
 */
export async function getOrCreateSubscription(userId: number) {
  const db = await getDb();
  if (!db) throw new Error('Database not available');

  const existing = await db.select().from(subscriptions).where(eq(subscriptions.userId, userId)).limit(1);
  if (existing.length > 0) return existing[0];

  const newSub: InsertSubscription = {
    id: `sub_${Date.now()}`,
    userId,
    plan: 'free',
    mergesThisMonth: 0,
    mergesLimit: 5,
  };

  await db.insert(subscriptions).values(newSub);
  return newSub;
}

export async function updateSubscription(userId: number, updates: Partial<InsertSubscription>) {
  const db = await getDb();
  if (!db) throw new Error('Database not available');
  return db.update(subscriptions).set(updates).where(eq(subscriptions.userId, userId));
}

export async function incrementMergeCount(userId: number) {
  const db = await getDb();
  if (!db) throw new Error('Database not available');
  const sub = await getOrCreateSubscription(userId);
  const newCount = (sub.mergesThisMonth || 0) + 1;
  return updateSubscription(userId, { mergesThisMonth: newCount });
}

/**
 * Check if user can perform merge (freemium gate)
 */
export async function canPerformMerge(userId: number): Promise<{
  allowed: boolean;
  mergesRemaining: number;
  mergesLimit: number;
  plan: 'free' | 'premium';
}> {
  const db = await getDb();
  if (!db) throw new Error('Database not available');

  const sub = await getOrCreateSubscription(userId);
  const mergesThisMonth = sub.mergesThisMonth || 0;
  const mergesLimit = sub.mergesLimit || 5;
  const plan = sub.plan || 'free';

  // Premium users have unlimited merges (mergesLimit = Infinity or very large number)
  const allowed = plan === 'premium' || mergesThisMonth < mergesLimit;
  const mergesRemaining = plan === 'premium' 
    ? Infinity 
    : Math.max(0, mergesLimit - mergesThisMonth);

  return {
    allowed,
    mergesRemaining,
    mergesLimit,
    plan,
  };
}

/**
 * Reset merge count for all users (monthly cron job)
 */
export async function resetMonthlyMergeCounts() {
  const db = await getDb();
  if (!db) throw new Error('Database not available');

  // Reset mergesThisMonth for all free tier users
  await db.update(subscriptions)
    .set({ mergesThisMonth: 0 })
    .where(eq(subscriptions.plan, 'free'));

  console.log('[Database] Monthly merge counts reset');
}

