  private async mergeNodesBatched(
    nodesA: EnvelopeNode[],
    nodesB: EnvelopeNode[],
    batchSize: number
  ): Promise<EnvelopeNode[]> {
    const nodeMap = new Map<string, EnvelopeNode>();
    const allNodes = [...nodesA, ...nodesB];

    // Process in batches
    for (let i = 0; i < allNodes.length; i += batchSize) {
      const batch = allNodes.slice(i, i + batchSize);

      batch.forEach((node) => {
        if (nodeMap.has(node.id)) {
          const existing = nodeMap.get(node.id)!;
          // Average confidences
          existing.confidence = Math.round((existing.confidence + node.confidence) / 2);
          // Merge parent nodes
