        consensusScore,
        nodesMerged: mergedNodes.length,
        edgesMerged: mergedEdges.length,
        completedAt: new Date(),
      };

      await createMerge(dbMerge);

      // Log audit entry
      await logAuditEntry({
        id: `audit_${nanoid()}`,
        userId,
        actionType: 'merge',
        resourceType: 'merge',
        resourceId: mergeId,
        details: JSON.stringify({
          envelopeAId: envelopeA.id,
          envelopeBId: envelopeB.id,
          resultId: resultEnvelope.id,
          consensusScore,
          conflictCount: conflictResolutions.length,
          totalNodes,
          batched: totalNodes > batchSize,
        }),
      });

      return {
        resultEnvelope,
        mergeId,
        consensusScore,
        conflictResolutions,
      };
    } catch (error) {
      // Log failed merge attempt
      await logAuditEntry({
        id: `audit_${nanoid()}`,
        userId,
        actionType: 'merge_failed',
        resourceType: 'merge',
        resourceId: mergeId,
        details: JSON.stringify({
          envelopeAId: envelopeA.id,
          envelopeBId: envelopeB.id,
          error: (error as Error).message,
          totalNodes,
        }),
      });
      throw error;
    }
  }

  /**
   * Merge nodes: deduplicate by ID and average confidences
   */
  private mergeNodes(nodesA: EnvelopeNode[], nodesB: EnvelopeNode[]): EnvelopeNode[] {
    const nodeMap = new Map<string, EnvelopeNode>();

    // Add nodes from A
    nodesA.forEach((node) => {
      nodeMap.set(node.id, { ...node });
    });

    // Merge nodes from B
    nodesB.forEach((node) => {
      if (nodeMap.has(node.id)) {
        const existing = nodeMap.get(node.id)!;
        // Average confidences
        existing.confidence = Math.round((existing.confidence + node.confidence) / 2);
        // Merge parent nodes
        existing.parentNodes = Array.from(
          new Set([...existing.parentNodes, ...node.parentNodes])
        );
      } else {
        nodeMap.set(node.id, { ...node });
      }
    });

    return Array.from(nodeMap.values());
  }

  /**
   * Merge edges: deduplicate and add federation edges with decay
   */
  private mergeEdges(edgesA: EnvelopeEdge[], edgesB: EnvelopeEdge[]): EnvelopeEdge[] {
    const edgeSet = new Set<string>();
    const edges: EnvelopeEdge[] = [];

    const addEdge = (edge: EnvelopeEdge) => {
      const key = `${edge.from}-${edge.to}-${edge.type}`;
      if (!edgeSet.has(key)) {
        edgeSet.add(key);
        edges.push(edge);
      }
    };

    // Add edges from both envelopes
    edgesA.forEach(addEdge);
    edgesB.forEach(addEdge);

    // Add federation edges between the two envelopes with confidence decay
    edges.push({
      from: `envelope_${edgesA[0]?.from || 'a'}`,
      to: `envelope_${edgesB[0]?.from || 'b'}`,
      type: 'federation',
      confidence: 80, // Federation decay: 0.80
    });

    return edges;
  }

  /**
   * Detect conflicts between envelopes
   * Enhanced with irreconcilable conflict detection
   */
  private detectConflicts(
    nodesA: EnvelopeNode[],
    nodesB: EnvelopeNode[]
  ): ConflictResolution[] {
    const conflicts: ConflictResolution[] = [];
    const nodeMapB = new Map(nodesB.map((n) => [n.id, n]));

    nodesA.forEach((nodeA) => {
      const nodeB = nodeMapB.get(nodeA.id);
      if (nodeB && nodeA.content !== nodeB.content) {
        const confidenceDiff = Math.abs(nodeA.confidence - nodeB.confidence);

        // If confidence difference is very small (< 5%), mark as irreconcilable
        if (confidenceDiff < 5) {
          conflicts.push({
            nodeId: nodeA.id,
            preferred: 'irreconcilable',
            reason: 'Confidence difference too small to auto-resolve',
            confidenceA: nodeA.confidence,
            confidenceB: nodeB.confidence,
          });
        } else {
          // Confidence-based conflict resolution: prefer higher confidence
          const resolution: ConflictResolution =
            nodeA.confidence >= nodeB.confidence
              ? {
                  nodeId: nodeA.id,
                  preferred: 'A',
                  reason: `Higher confidence in A (${nodeA.confidence}% vs ${nodeB.confidence}%)`,
                  confidenceA: nodeA.confidence,
                  confidenceB: nodeB.confidence,
                }
              : {
                  nodeId: nodeB.id,
                  preferred: 'B',
                  reason: `Higher confidence in B (${nodeB.confidence}% vs ${nodeA.confidence}%)`,
                  confidenceA: nodeA.confidence,
                  confidenceB: nodeB.confidence,
                };

          conflicts.push(resolution);
        }
      }
    });

    return conflicts;
  }

  /**
   * Merge nodes in batches for large envelopes (prevents LevelDB bloat)
   */
  private async mergeNodesBatched(
    nodesA: EnvelopeNode[],
    nodesB: EnvelopeNode[],
    batchSize: number
  ): Promise<EnvelopeNode[]> {
    const nodeMap = new Map<string, EnvelopeNode>();
    const allNodes = [...nodesA, ...nodesB];

    // Process in batches
    for (let i = 0; i < allNodes.length; i += batchSize) {
      const batch = allNodes.slice(i, i + batchSize);

      batch.forEach((node) => {
        if (nodeMap.has(node.id)) {
          const existing = nodeMap.get(node.id)!;
          // Average confidences
          existing.confidence = Math.round((existing.confidence + node.confidence) / 2);
          // Merge parent nodes
          existing.parentNodes = Array.from(
            new Set([...existing.parentNodes, ...node.parentNodes])
          );
        } else {
          nodeMap.set(node.id, { ...node });
        }
      });

      // Yield to event loop to prevent blocking
      await new Promise(resolve => setImmediate(resolve));
    }

    return Array.from(nodeMap.values());
  }

  /**
   * Compute consensus score based on merged nodes and conflicts
   */
  private computeConsensusScore(
    nodes: EnvelopeNode[],
    conflicts: ConflictResolution[]
  ): number {
    if (nodes.length === 0) return 0;

    const avgConfidence = nodes.reduce((sum, n) => sum + n.confidence, 0) / nodes.length;
    const conflictPenalty = (conflicts.length / nodes.length) * 20; // Up to 20% penalty

    return Math.max(0, Math.round(avgConfidence - conflictPenalty));
  }
}

/**
 * Conflict Resolution: Tracks how conflicts were resolved
 */
export interface ConflictResolution {
  nodeId: string;
  preferred: 'A' | 'B' | 'deferred' | 'irreconcilable';
  reason: string;
  confidenceA: number;
  confidenceB: number;
}

/**
 * Enhanced conflict detection with irreconcilable state support
 */
export interface EnhancedConflictResolution extends ConflictResolution {
  state: 'resolved' | 'deferred' | 'irreconcilable';
  requiresUserInput: boolean;
}

