```typescript
import { Request, Response } from 'express';
import { verifyWebhookSignature, handleCheckoutSessionCompleted, handleSubscriptionUpdated, handleSubscriptionDeleted } from '../stripe-handler';

/**
 * Stripe Webhook Endpoint
 * Securely handles Stripe webhook events with signature verification
 * 
 * Route: POST /api/stripe/webhook
 */
export async function stripeWebhookHandler(req: Request, res: Response) {
  const signature = req.headers['stripe-signature'] as string;

  if (!signature) {
    console.error('[Stripe Webhook] Missing signature header');
    return res.status(400).json({ error: 'Missing signature' });
  }

  // Verify webhook signature
  const event = verifyWebhookSignature(req.body, signature);

  if (!event) {
    console.error('[Stripe Webhook] Invalid signature');
    return res.status(400).json({ error: 'Invalid signature' });
  }

  // Handle different event types
  try {
    switch (event.type) {
      case 'checkout.session.completed':
        await handleCheckoutSessionCompleted(event);
        break;

      case 'customer.subscription.updated':
        await handleSubscriptionUpdated(event);
        break;

      case 'customer.subscription.deleted':
        await handleSubscriptionDeleted(event);
        break;

      case 'invoice.payment_succeeded':
        // Handle successful payment
        console.log('[Stripe Webhook] Payment succeeded:', event.id);
        break;

      case 'invoice.payment_failed':
        // Handle failed payment
        console.warn('[Stripe Webhook] Payment failed:', event.id);
        break;

      default:
        console.log(`[Stripe Webhook] Unhandled event type: ${event.type}`);
    }

    // Acknowledge receipt
    res.json({ received: true });
  } catch (error) {
    console.error('[Stripe Webhook] Error processing webhook:', error);
    res.status(500).json({ error: 'Webhook processing failed' });
  }
}

