```typescript
/**
 * Universal Chat Parser
 * Supports multiple chat export formats with intelligent detection and parsing
 */

export type ChatFormat = 
  | 'chatgpt' 
  | 'claude' 
  | 'gemini' 
  | 'copilot' 
  | 'markdown' 
  | 'csv' 
  | 'txt' 
  | 'json_generic'
  | 'unknown';

export interface ParsedMessage {
  id: string;
  role: 'user' | 'assistant' | 'system' | 'unknown';
  content: string;
  timestamp: string;
  confidence: number;
  metadata?: Record<string, any>;
}

export interface ParseResult {
  format: ChatFormat;
  title: string;
  messages: ParsedMessage[];
  metadata: {
    source: string;
    messageCount: number;
    dateRange?: { start: string; end: string };
    confidence: number;
  };
}

/**
 * Universal Chat Parser - Detects and parses multiple chat export formats
 */
export class UniversalChatParser {
  /**
   * Parse any chat export format
   */
  async parse(file: File): Promise<ParseResult> {
    const fileName = file.name.toLowerCase();
    const extension = fileName.split('.').pop() || '';

    // Try JSON first (most common)
    if (extension === 'json') {
      return this.parseJSON(file);
    }

    // Try Markdown
    if (extension === 'md' || extension === 'markdown') {
      return this.parseMarkdown(file);
    }

    // Try CSV
    if (extension === 'csv') {
      return this.parseCSV(file);
    }

    // Try plain text
    if (extension === 'txt' || extension === 'text') {
      return this.parseText(file);
    }

    // Fallback: try to detect from content
    return this.parseAutoDetect(file);
  }

  /**
   * Parse JSON formats (ChatGPT, Claude, Gemini, generic)
   */
  private async parseJSON(file: File): Promise<ParseResult> {
    const text = await file.text();
    let data: any;

    try {
      data = JSON.parse(text);
    } catch {
      throw new Error('Invalid JSON file');
    }

    // ChatGPT format detection
    if (Array.isArray(data) && data[0]?.['messages']) {
      return this.parseChatGPT(data);
    }

    // Claude format detection
    if (data.conversation_id || (Array.isArray(data) && data[0]?.['role'])) {
      return this.parseClaude(data);
    }

    // Gemini format detection
    if (data.candidates || data.parts) {
      return this.parseGemini(data);
    }

    // Generic JSON array of messages
    if (Array.isArray(data) && data.every((item: any) => item.role || item.content)) {
      return this.parseGenericJSON(data, file.name);
    }

    throw new Error('Unsupported JSON format');
  }

  /**
   * Parse ChatGPT export format
   */
  private parseChatGPT(data: any[]): ParseResult {
    const conversation = data[0];
    const messages = (conversation.messages || []).map((msg: any, idx: number) => ({
      id: `msg_${idx}`,
      role: this.normalizeRole(msg.role || 'user'),
      content: this.extractContent(msg),
      timestamp: msg.create_time 
        ? new Date(msg.create_time * 1000).toISOString()
        : new Date().toISOString(),
      confidence: 100,
      metadata: {
        messageId: msg.id,
        model: msg.model,
      },
    }));

    return {
      format: 'chatgpt',
      title: conversation.title || 'ChatGPT Conversation',
      messages,
      metadata: {
        source: 'chatgpt',
        messageCount: messages.length,
        confidence: 100,
      },
    };
  }

  /**
   * Parse Claude export format
   */
  private parseClaude(data: any): ParseResult {
    const messages = (Array.isArray(data) ? data : data.messages || []).map((msg: any, idx: number) => ({
      id: `msg_${idx}`,
      role: this.normalizeRole(msg.role || 'user'),
      content: this.extractContent(msg),
      timestamp: msg.timestamp || new Date().toISOString(),
      confidence: 100,
      metadata: {
        conversationId: data.conversation_id,
      },
    }));

    return {
      format: 'claude',
      title: data.title || 'Claude Conversation',
      messages,
      metadata: {
        source: 'claude',
        messageCount: messages.length,
        confidence: 100,
      },
    };
  }

  /**
   * Parse Gemini export format
   */
  private parseGemini(data: any): ParseResult {
    const messages: ParsedMessage[] = [];
    let idx = 0;

    // Handle Gemini's nested structure
    const processCandidates = (candidates: any[]) => {
      candidates.forEach((candidate: any) => {
        if (candidate.content?.parts) {
          candidate.content.parts.forEach((part: any) => {
            messages.push({
              id: `msg_${idx++}`,
              role: candidate.role === 'model' ? 'assistant' : 'user',
              content: part.text || JSON.stringify(part),
              timestamp: new Date().toISOString(),
              confidence: 95, // Slightly lower for nested structure
              metadata: {
                model: candidate.modelVersion,
              },
            });
          });
        }
      });
    };

    if (data.candidates) {
      processCandidates(data.candidates);
    } else if (Array.isArray(data)) {
      data.forEach((item: any) => {
        if (item.candidates) processCandidates(item.candidates);
      });
    }

    return {
      format: 'gemini',
      title: data.title || 'Gemini Conversation',
      messages,
      metadata: {
        source: 'gemini',
        messageCount: messages.length,
        confidence: 95,
      },
    };
  }

  /**
   * Parse generic JSON format
   */
  private parseGenericJSON(data: any[], fileName: string): ParseResult {
    const messages = data.map((msg: any, idx: number) => ({
      id: msg.id || `msg_${idx}`,
      role: this.normalizeRole(msg.role || msg.sender || 'user'),
      content: this.extractContent(msg),
      timestamp: msg.timestamp || msg.date || msg.created_at || new Date().toISOString(),
      confidence: 90, // Lower confidence for generic format
      metadata: msg.metadata || {},
    }));

    return {
      format: 'json_generic',
      title: fileName.replace('.json', ''),
      messages,
      metadata: {
        source: 'generic_json',
        messageCount: messages.length,
        confidence: 90,
      },
    };
  }

  /**
   * Parse Markdown format
   */
  private async parseMarkdown(file: File): Promise<ParseResult> {
    const text = await file.text();
    const lines = text.split('\n');
    const messages: ParsedMessage[] = [];
    let currentRole: 'user' | 'assistant' | 'system' = 'user';
    let currentContent: string[] = [];
    let idx = 0;

    for (const line of lines) {
      // Detect role markers
      if (line.match(/^#+\s*(User|You|Human)/i)) {
        if (currentContent.length > 0) {
          messages.push(this.createMessage(idx++, currentRole, currentContent.join('\n')));
          currentContent = [];
        }
        currentRole = 'user';
      } else if (line.match(/^#+\s*(Assistant|AI|Bot|ChatGPT|Claude|Gemini)/i)) {
        if (currentContent.length > 0) {
          messages.push(this.createMessage(idx++, currentRole, currentContent.join('\n')));
          currentContent = [];
        }
        currentRole = 'assistant';
      } else if (line.trim().startsWith('**') && line.includes(':')) {
        // Bold headers like **User:** or **Assistant:**
        if (currentContent.length > 0) {
          messages.push(this.createMessage(idx++, currentRole, currentContent.join('\n')));
          currentContent = [];
        }
        if (line.toLowerCase().includes('user') || line.toLowerCase().includes('you')) {
          currentRole = 'user';
        } else {
          currentRole = 'assistant';
        }
      } else if (line.trim().length > 0) {
        currentContent.push(line);
      }
    }

    // Add last message
    if (currentContent.length > 0) {
      messages.push(this.createMessage(idx++, currentRole, currentContent.join('\n')));
    }

    return {
      format: 'markdown',
      title: file.name.replace('.md', '').replace('.markdown', ''),
      messages,
      metadata: {
        source: 'markdown',
        messageCount: messages.length,
        confidence: 85, // Lower confidence for markdown parsing
      },
    };
  }

  /**
   * Parse CSV format
   */
  private async parseCSV(file: File): Promise<ParseResult> {
    const text = await file.text();
    const lines = text.split('\n').filter(line => line.trim());
    const headers = lines[0].split(',').map(h => h.trim().toLowerCase());
    const messages: ParsedMessage[] = [];

    const roleIdx = headers.findIndex(h => h.includes('role') || h.includes('sender'));
    const contentIdx = headers.findIndex(h => h.includes('content') || h.includes('message') || h.includes('text'));
    const timestampIdx = headers.findIndex(h => h.includes('time') || h.includes('date'));

    for (let i = 1; i < lines.length; i++) {
      const values = this.parseCSVLine(lines[i]);
      if (values.length > Math.max(roleIdx, contentIdx)) {
        messages.push({
          id: `msg_${i - 1}`,
          role: this.normalizeRole(values[roleIdx] || 'user'),
          content: values[contentIdx] || '',
          timestamp: values[timestampIdx] || new Date().toISOString(),
          confidence: 90,
        });
      }
    }

    return {
      format: 'csv',
      title: file.name.replace('.csv', ''),
      messages,
      metadata: {
        source: 'csv',
        messageCount: messages.length,
        confidence: 90,
      },
    };
  }

  /**
   * Parse plain text format
   */
  private async parseText(file: File): Promise<ParseResult> {
    const text = await file.text();
    const messages: ParsedMessage[] = [];

    // Try to detect patterns
    const patterns = [
      /(User|You):\s*(.+)/gi,
      /(Assistant|AI|Bot):\s*(.+)/gi,
      /(Human):\s*(.+)/gi,
    ];

    let idx = 0;
    const lines = text.split('\n');

    for (const line of lines) {
      if (line.match(/^(User|You|Human):/i)) {
        const match = line.match(/^[^:]+:\s*(.+)/);
        if (match) {
          messages.push(this.createMessage(idx++, 'user', match[1]));
        }
      } else if (line.match(/^(Assistant|AI|Bot|ChatGPT|Claude|Gemini):/i)) {
        const match = line.match(/^[^:]+:\s*(.+)/);
        if (match) {
          messages.push(this.createMessage(idx++, 'assistant', match[1]));
        }
      } else if (line.trim().length > 0) {
        // Continuation of previous message or new user message
        if (messages.length === 0) {
          messages.push(this.createMessage(idx++, 'user', line));
        } else {
          const lastMsg = messages[messages.length - 1];
          lastMsg.content += '\n' + line;
        }
      }
    }

    return {
      format: 'txt',
      title: file.name.replace('.txt', '').replace('.text', ''),
      messages,
      metadata: {
        source: 'text',
        messageCount: messages.length,
        confidence: 75, // Lower confidence for plain text
      },
    };
  }

  /**
   * Auto-detect format from content
   */
  private async parseAutoDetect(file: File): Promise<ParseResult> {
    const text = await file.text();

    // Try JSON
    try {
      const data = JSON.parse(text);
      return this.parseGenericJSON(Array.isArray(data) ? data : [data], file.name);
    } catch {
      // Not JSON, try markdown
      if (text.includes('#') || text.includes('**')) {
        return this.parseMarkdown(file);
      }
      // Try text
      return this.parseText(file);
    }
  }

  /**
   * Helper: Extract content from message object
   */
  private extractContent(msg: any): string {
    if (typeof msg.content === 'string') {
      return msg.content;
    }
    if (msg.content?.text) {
      return msg.content.text;
    }
    if (msg.text) {
      return msg.text;
    }
    if (Array.isArray(msg.content)) {
      return msg.content.map((c: any) => c.text || c).join('\n');
    }
    return JSON.stringify(msg);
  }

  /**
   * Helper: Normalize role names
   */
  private normalizeRole(role: string): 'user' | 'assistant' | 'system' | 'unknown' {
    const normalized = role.toLowerCase().trim();
    if (normalized === 'user' || normalized === 'human' || normalized === 'you') {
      return 'user';
    }
    if (normalized === 'assistant' || normalized === 'ai' || normalized === 'bot' || normalized === 'model') {
      return 'assistant';
    }
    if (normalized === 'system') {
      return 'system';
    }
    return 'unknown';
  }

  /**
   * Helper: Create message object
   */
  private createMessage(idx: number, role: 'user' | 'assistant' | 'system', content: string): ParsedMessage {
    return {
      id: `msg_${idx}`,
      role,
      content: content.trim(),
      timestamp: new Date().toISOString(),
      confidence: 100,
    };
  }

  /**
   * Helper: Parse CSV line (handles quoted values)
   */
  private parseCSVLine(line: string): string[] {
    const result: string[] = [];
    let current = '';
    let inQuotes = false;

    for (let i = 0; i < line.length; i++) {
      const char = line[i];
      if (char === '"') {
        inQuotes = !inQuotes;
      } else if (char === ',' && !inQuotes) {
        result.push(current.trim());
        current = '';
      } else {
        current += char;
      }
    }
    result.push(current.trim());

    return result;
  }
}

