import React, { useState } from 'react';
import { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Card } from '@/components/ui/card';
import { CheckCircle, Zap, Infinity, Shield, Sparkles, Loader2 } from 'lucide-react';
import { trpc } from '@/lib/trpc';
import { toast } from 'sonner';
import { createCheckoutSession } from '../stripe-handler';

interface SubscriptionModalProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  userEmail?: string;
  userName?: string;
}

/**
 * Subscription Modal Component
 * Handles Stripe checkout for Premium subscriptions
 */
export function SubscriptionModal({ open, onOpenChange, userEmail, userName }: SubscriptionModalProps) {
  const [isLoading, setIsLoading] = useState(false);
  const [selectedPlan, setSelectedPlan] = useState<'monthly' | 'annual'>('monthly');

  const handleSubscribe = async () => {
    if (!userEmail) {
      toast.error('Please sign in to subscribe');
      return;
    }

    setIsLoading(true);
    try {
      // Get price ID from environment
      const priceId = selectedPlan === 'monthly' 
        ? process.env.NEXT_PUBLIC_STRIPE_PRICE_ID_MONTHLY
        : process.env.NEXT_PUBLIC_STRIPE_PRICE_ID_ANNUAL;

      if (!priceId) {
        toast.error('Subscription pricing not configured. Please contact support.');
        return;
      }

      // Create checkout session
      const checkoutUrl = await createCheckoutSession(
        0, // userId will be set from session
        userEmail,
        userName || 'User',
        priceId,
        window.location.origin
      );

      if (checkoutUrl) {
        // Redirect to Stripe checkout
        window.location.href = checkoutUrl;
      } else {
        toast.error('Failed to create checkout session');
      }
    } catch (error) {
      console.error('Subscription error:', error);
      toast.error('Failed to start subscription. Please try again.');
    } finally {
      setIsLoading(false);
    }
  };

  const plans = {
    monthly: {
      price: '€4.99',
      period: 'per month',
      priceId: process.env.NEXT_PUBLIC_STRIPE_PRICE_ID_MONTHLY,
      savings: null,
    },
    annual: {
      price: '€49.99',
      period: 'per year',
      priceId: process.env.NEXT_PUBLIC_STRIPE_PRICE_ID_ANNUAL,
      savings: 'Save 17%',
    },
  };

  const features = [
    {
      icon: Infinity,
      title: 'Unlimited Merges',
      description: 'Merge as many conversations as you want, no limits',
    },
    {
      icon: Sparkles,
      title: 'Advanced Analytics',
      description: 'Deep insights into conversation patterns and knowledge evolution',
    },
    {
      icon: Shield,
      title: 'Enhanced Security',
      description: 'Priority support and advanced audit trail features',
    },
    {
      icon: Zap,
      title: 'Agent Packs (Coming Soon)',
      description: 'Pre-built agents for bias detection and automated insights',
    },
  ];

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle className="text-2xl">Upgrade to Premium</DialogTitle>
          <DialogDescription>
            Unlock unlimited merges and advanced features to build comprehensive knowledge graphs
          </DialogDescription>
        </DialogHeader>

        <div className="space-y-6 mt-4">
          {/* Plan Selection */}
          <div className="grid grid-cols-2 gap-4">
            <Card
              className={`p-4 cursor-pointer transition-all border-2 ${
                selectedPlan === 'monthly'
                  ? 'border-emerald-500 bg-emerald-50 dark:bg-emerald-900/20'
                  : 'border-border hover:border-emerald-300'
              }`}
              onClick={() => setSelectedPlan('monthly')}
            >
              <div className="flex items-center justify-between mb-2">
                <h3 className="font-semibold">Monthly</h3>
                {selectedPlan === 'monthly' && (
                  <CheckCircle className="w-5 h-5 text-emerald-600" />
                )}
              </div>
              <div className="text-2xl font-bold">{plans.monthly.price}</div>
              <div className="text-sm text-muted-foreground">{plans.monthly.period}</div>
            </Card>

            <Card
              className={`p-4 cursor-pointer transition-all border-2 relative ${
                selectedPlan === 'annual'
                  ? 'border-emerald-500 bg-emerald-50 dark:bg-emerald-900/20'
                  : 'border-border hover:border-emerald-300'
              }`}
              onClick={() => setSelectedPlan('annual')}
            >
              {plans.annual.savings && (
                <div className="absolute -top-2 -right-2 bg-amber-500 text-white text-xs px-2 py-1 rounded-full font-semibold">
                  {plans.annual.savings}
                </div>
              )}
              <div className="flex items-center justify-between mb-2">
                <h3 className="font-semibold">Annual</h3>
                {selectedPlan === 'annual' && (
                  <CheckCircle className="w-5 h-5 text-emerald-600" />
                )}
              </div>
              <div className="text-2xl font-bold">{plans.annual.price}</div>
              <div className="text-sm text-muted-foreground">{plans.annual.period}</div>
            </Card>
          </div>

          {/* Features List */}
          <div className="space-y-3">
            <h4 className="font-semibold text-sm text-muted-foreground uppercase">Premium Features</h4>
            {features.map((feature, idx) => (
              <div key={idx} className="flex gap-3 p-3 rounded-lg border border-border">
                <feature.icon className="w-5 h-5 text-emerald-600 flex-shrink-0 mt-0.5" />
                <div>
                  <h5 className="font-semibold text-sm">{feature.title}</h5>
                  <p className="text-sm text-muted-foreground">{feature.description}</p>
                </div>
              </div>
            ))}
          </div>

          {/* Security Note */}
          <Card className="p-4 bg-slate-50 dark:bg-slate-800 border-slate-200 dark:border-slate-700">
            <div className="flex gap-2 text-sm text-muted-foreground">
              <Shield className="w-4 h-4 flex-shrink-0 mt-0.5" />
              <div>
                <strong className="text-foreground">Your data remains sovereign.</strong> Premium adds 
                unlimited merging capabilities, not data access restrictions. All data is encrypted 
                and cryptographically signed regardless of tier.
              </div>
            </div>
          </Card>

          {/* CTA */}
          <div className="flex gap-3">
            <Button
              variant="outline"
              className="flex-1"
              onClick={() => onOpenChange(false)}
              disabled={isLoading}
            >
              Cancel
            </Button>
            <Button
              className="flex-1 bg-emerald-600 hover:bg-emerald-700"
              onClick={handleSubscribe}
              disabled={isLoading || !userEmail}
            >
              {isLoading ? (
                <>
                  <Loader2 className="w-4 h-4 mr-2 animate-spin" />
                  Processing...
                </>
              ) : (
                <>
                  Subscribe to Premium
                  <Zap className="w-4 h-4 ml-2" />
                </>
              )}
            </Button>
          </div>

          <p className="text-xs text-center text-muted-foreground">
            By subscribing, you agree to our terms of service. Cancel anytime.
          </p>
        </div>
      </DialogContent>
    </Dialog>
  );
}

