import { resetMonthlyMerges } from '../../../server/cron/monthly-reset';
import { Request, Response } from 'express';

/**
 * Vercel Cron Endpoint for Monthly Reset
 * 
 * Route: GET /api/cron/monthly-reset
 * 
 * This endpoint is called by Vercel Cron on the 1st of every month.
 * Make sure to protect it with a secret token in production.
 */
export default async function handler(req: Request, res: Response) {
  // Verify cron secret (optional but recommended)
  const cronSecret = req.headers['authorization']?.replace('Bearer ', '');
  const expectedSecret = process.env.CRON_SECRET;

  if (expectedSecret && cronSecret !== expectedSecret) {
    console.error('[Cron] Unauthorized access attempt');
    return res.status(401).json({ error: 'Unauthorized' });
  }

  try {
    const result = await resetMonthlyMerges();
    return res.status(200).json(result);
  } catch (error) {
    console.error('[Cron] Error:', error);
    return res.status(500).json({ 
      error: 'Cron job failed',
      message: (error as Error).message 
    });
  }
}

