/**
 * Environment Variable Validation
 * Validates required environment variables at startup
 */

interface EnvConfig {
  DATABASE_URL?: string;
  STRIPE_SECRET_KEY?: string;
  STRIPE_WEBHOOK_SECRET?: string;
  STRIPE_PRICE_ID_MONTHLY?: string;
  STRIPE_PRICE_ID_ANNUAL?: string;
  NEXT_PUBLIC_STRIPE_PRICE_ID_MONTHLY?: string;
  NEXT_PUBLIC_STRIPE_PRICE_ID_ANNUAL?: string;
  CRON_SECRET?: string;
  NODE_ENV?: string;
}

const requiredEnvVars = {
  production: [
    'DATABASE_URL',
    'STRIPE_SECRET_KEY',
    'STRIPE_WEBHOOK_SECRET',
    'STRIPE_PRICE_ID_MONTHLY',
    'STRIPE_PRICE_ID_ANNUAL',
  ],
  development: [
    'DATABASE_URL',
  ],
};

export function validateEnv(): { valid: boolean; errors: string[] } {
  const errors: string[] = [];
  const env = (process.env.NODE_ENV || 'development') as 'production' | 'development';
  const required = requiredEnvVars[env] || requiredEnvVars.development;

  for (const varName of required) {
    if (!process.env[varName]) {
      errors.push(`Missing required environment variable: ${varName}`);
    }
  }

  // Validate Stripe keys format
  if (process.env.STRIPE_SECRET_KEY && !process.env.STRIPE_SECRET_KEY.startsWith('sk_')) {
    errors.push('STRIPE_SECRET_KEY must start with "sk_"');
  }

  if (process.env.STRIPE_WEBHOOK_SECRET && !process.env.STRIPE_WEBHOOK_SECRET.startsWith('whsec_')) {
    errors.push('STRIPE_WEBHOOK_SECRET must start with "whsec_"');
  }

  return {
    valid: errors.length === 0,
    errors,
  };
}

export function getEnvConfig(): EnvConfig {
  return {
    DATABASE_URL: process.env.DATABASE_URL,
    STRIPE_SECRET_KEY: process.env.STRIPE_SECRET_KEY,
    STRIPE_WEBHOOK_SECRET: process.env.STRIPE_WEBHOOK_SECRET,
    STRIPE_PRICE_ID_MONTHLY: process.env.STRIPE_PRICE_ID_MONTHLY,
    STRIPE_PRICE_ID_ANNUAL: process.env.STRIPE_PRICE_ID_ANNUAL,
    NEXT_PUBLIC_STRIPE_PRICE_ID_MONTHLY: process.env.NEXT_PUBLIC_STRIPE_PRICE_ID_MONTHLY,
    NEXT_PUBLIC_STRIPE_PRICE_ID_ANNUAL: process.env.NEXT_PUBLIC_STRIPE_PRICE_ID_ANNUAL,
    CRON_SECRET: process.env.CRON_SECRET,
    NODE_ENV: process.env.NODE_ENV,
  };
}

// Validate on import (server-side only)
if (typeof window === 'undefined') {
  const validation = validateEnv();
  if (!validation.valid && process.env.NODE_ENV === 'production') {
    console.error('❌ Environment validation failed:');
    validation.errors.forEach(error => console.error(`  - ${error}`));
    process.exit(1);
  } else if (!validation.valid) {
    console.warn('⚠️  Environment validation warnings:');
    validation.errors.forEach(error => console.warn(`  - ${error}`));
  }
}

