import React, { useCallback, useState } from 'react';
import { Upload, AlertCircle, CheckCircle } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Card } from '@/components/ui/card';
import { toast } from 'sonner';

interface FileImporterProps {
  onImport: (data: {
    title: string;
    nodes: Array<{
      id: string;
      role: string;
      content: string;
      timestamp: string;
      confidence: number;
      parentNodes: string[];
    }>;
    edges: Array<{
      from: string;
      to: string;
      type: 'follows' | 'federation' | 'conflict';
      confidence?: number;
    }>;
    sourceType: 'chatgpt' | 'claude' | 'manual';
  }) => void;
  isLoading?: boolean;
}

/**
 * File Importer Component
 * Handles drag-and-drop and file selection for ChatGPT/Claude JSON exports
 */
export const FileImporter: React.FC<FileImporterProps> = ({ onImport, isLoading }) => {
  const [isDragActive, setIsDragActive] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);

  const handleDrag = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === 'dragenter' || e.type === 'dragover') {
      setIsDragActive(true);
    } else if (e.type === 'dragleave') {
      setIsDragActive(false);
    }
  }, []);

  const parseFile = useCallback(async (file: File) => {
    try {
      setIsProcessing(true);

      // Validate file size (10MB limit)
      const MAX_FILE_SIZE = 10 * 1024 * 1024; // 10MB
      if (file.size > MAX_FILE_SIZE) {
        toast.error(`File too large. Maximum size is ${MAX_FILE_SIZE / 1024 / 1024}MB`);
        return;
      }

      // Validate file type
      const allowedExtensions = ['.json', '.md', '.markdown', '.csv', '.txt', '.text'];
      const fileExtension = '.' + file.name.split('.').pop()?.toLowerCase();
      if (!allowedExtensions.includes(fileExtension)) {
        toast.error(`Unsupported file type. Supported: ${allowedExtensions.join(', ')}`);
        return;
      }

      // Use universal parser
      const { UniversalChatParser } = await import('@/utils/universal-chat-parser');
      const parser = new UniversalChatParser();
      const result = await parser.parse(file);

      // Convert to envelope format
      const nodes = result.messages.map((msg, idx) => ({
        id: msg.id,
        role: msg.role === 'unknown' ? 'user' : msg.role,
        content: msg.content,
        timestamp: msg.timestamp,
        confidence: msg.confidence,
        parentNodes: idx > 0 ? [result.messages[idx - 1].id] : [],
      }));

      // Create sequential edges
      const edges = [];
      for (let i = 1; i < nodes.length; i++) {
        edges.push({
          from: nodes[i - 1].id,
          to: nodes[i].id,
          type: 'follows' as const,
          confidence: Math.min(nodes[i].confidence, nodes[i - 1].confidence),
        });
      }

      // Map format to sourceType
      const sourceTypeMap: Record<string, 'chatgpt' | 'claude' | 'manual'> = {
        chatgpt: 'chatgpt',
        claude: 'claude',
        gemini: 'manual',
        copilot: 'manual',
        markdown: 'manual',
        csv: 'manual',
        txt: 'manual',
        json_generic: 'manual',
        unknown: 'manual',
      };

      const sourceType = sourceTypeMap[result.format] || 'manual';

      onImport({
        title: result.title,
        nodes,
        edges,
        sourceType,
      });

      toast.success(
        `Imported ${nodes.length} messages from ${result.format} format ` +
        `(confidence: ${result.metadata.confidence}%)`
      );
    } catch (error) {
      toast.error(`Failed to parse file: ${(error as Error).message}`);
      console.error('Import error:', error);
    } finally {
      setIsProcessing(false);
    }
  }, [onImport]);

  const handleDrop = useCallback(
    (e: React.DragEvent) => {
      e.preventDefault();
      e.stopPropagation();
      setIsDragActive(false);

      const files = e.dataTransfer.files;
      if (files && files.length > 0) {
        parseFile(files[0]);
      }
    },
    [parseFile]
  );

  const handleFileSelect = useCallback(
    (e: React.ChangeEvent<HTMLInputElement>) => {
      if (e.target.files && e.target.files.length > 0) {
        parseFile(e.target.files[0]);
      }
    },
    [parseFile]
  );

  return (
    <Card className="w-full p-8">
      <div
        onDragEnter={handleDrag}
        onDragLeave={handleDrag}
        onDragOver={handleDrag}
        onDrop={handleDrop}
        className={`
          border-2 border-dashed rounded-lg p-8 text-center transition-colors
          ${isDragActive
            ? 'border-emerald-500 bg-emerald-50 dark:bg-emerald-900/20'
            : 'border-border hover:border-emerald-400'
          }
        `}
      >
        <div className="flex flex-col items-center gap-4">
          <div className={`p-3 rounded-full ${isDragActive ? 'bg-emerald-100 dark:bg-emerald-900' : 'bg-slate-100 dark:bg-slate-800'}`}>
            <Upload className={`w-6 h-6 ${isDragActive ? 'text-emerald-600' : 'text-muted-foreground'}`} />
          </div>

          <div>
            <h3 className="font-semibold text-foreground">
              {isProcessing ? 'Processing...' : 'Drop your chat export here'}
            </h3>
            <p className="text-sm text-muted-foreground mt-1">
              Supports ChatGPT, Claude, Gemini, Markdown, CSV, TXT, and more
            </p>
          </div>

          <div className="flex gap-2 items-center text-xs text-muted-foreground">
            <span>or</span>
            <label>
              <input
                type="file"
                accept=".json,.md,.markdown,.csv,.txt,.text"
                onChange={handleFileSelect}
                disabled={isLoading || isProcessing}
                className="hidden"
                id="file-input"
              />
              <Button
                variant="outline"
                size="sm"
                onClick={() => (document.getElementById('file-input') as HTMLInputElement)?.click()}
                disabled={isLoading || isProcessing}
              >
                Browse Files
              </Button>
            </label>
          </div>
        </div>
      </div>

      <div className="mt-6 space-y-3 text-sm">
        <div className="flex gap-2 items-start">
          <CheckCircle className="w-4 h-4 text-emerald-600 flex-shrink-0 mt-0.5" />
          <span className="text-muted-foreground">
            Your data is processed locally and encrypted with Ed25519 signatures
          </span>
        </div>
        <div className="flex gap-2 items-start">
          <CheckCircle className="w-4 h-4 text-emerald-600 flex-shrink-0 mt-0.5" />
          <span className="text-muted-foreground">
            Full audit trail maintained for forensic purposes
          </span>
        </div>
        <div className="flex gap-2 items-start">
