    createCheckout: protectedProcedure
      .input(z.object({
        priceId: z.string(),
      }))
      .mutation(async ({ ctx, input }) => {
        const { createCheckoutSession } = await import('./stripe-handler');
        const origin = ctx.req.headers.origin || 'http://localhost:3000';
        const url = await createCheckoutSession(
          ctx.user.id,
          ctx.user.email || '',
          ctx.user.name || 'User',
          input.priceId,
          origin as string
        );
        return { url };
      }),
    status: protectedProcedure.query(async ({ ctx }) => {
      const { getSubscriptionStatus } = await import('./stripe-handler');
      return getSubscriptionStatus(ctx.user.id);
    }),
  }),
  auth: router({
    me: publicProcedure.query(opts => opts.ctx.user),
    logout: publicProcedure.mutation(({ ctx }) => {
      const cookieOptions = getSessionCookieOptions(ctx.req);
      ctx.res.clearCookie(COOKIE_NAME, { ...cookieOptions, maxAge: -1 });
      return {
        success: true,
      } as const;
    }),
  }),

  envelopes: router({
    list: protectedProcedure.query(async ({ ctx }) => {
      const { getEnvelopesByUser } = await import('./db');
      return getEnvelopesByUser(ctx.user.id);
    }),
    create: protectedProcedure
      .input(z.object({
        title: z.string(),
        description: z.string().optional(),
        nodes: z.array(z.object({
          id: z.string(),
          role: z.string(),
          content: z.string(),
          timestamp: z.string(),
          confidence: z.number(),
          parentNodes: z.array(z.string()),
        })),
        edges: z.array(z.object({
          from: z.string(),
          to: z.string(),
          type: z.enum(['follows', 'federation', 'conflict']),
          confidence: z.number().optional(),
        })),
        sourceType: z.enum(['chatgpt', 'claude', 'manual']),
      }))
      .mutation(async ({ ctx, input }) => {
        const { EnvelopeOperations } = await import('./envelope-ops');
        const { CAS_Bridge } = await import('./cas-bridge');
        const cas = new CAS_Bridge();
        await cas.open();
        const envelopeOps = new EnvelopeOperations(cas);
        const envelope = await envelopeOps.createEnvelope(
          ctx.user.id,
          input.title,
          input.nodes,
          input.edges,
          input.sourceType,
          input.description
        );
        await cas.close();
        return envelope;
      }),
  }),
  merges: router({
    list: protectedProcedure.query(async ({ ctx }) => {
      const { getMergesByUser } = await import('./db');
      return getMergesByUser(ctx.user.id);
    }),
    create: protectedProcedure
      .input(z.object({
        envelopeAId: z.string(),
        envelopeBId: z.string(),
      }))
      .mutation(async ({ ctx, input }) => {
        const { getEnvelopeById, canPerformMerge, incrementMergeCount } = await import('./db');
        const { MergeOperations } = await import('./merge-ops');
        const { CAS_Bridge } = await import('./cas-bridge');

        // Freemium gate: Check if user can perform merge
        const mergeCheck = await canPerformMerge(ctx.user.id);
        if (!mergeCheck.allowed) {
          throw new TRPCError({ 
            code: 'FORBIDDEN', 
            message: `Merge limit reached. You have ${mergeCheck.mergesRemaining} merges remaining this month. Upgrade to Premium for unlimited merges.` 
          });
        }

        const envelopeAResult = await getEnvelopeById(input.envelopeAId);
        const envelopeBResult = await getEnvelopeById(input.envelopeBId);

        if (!envelopeAResult || !envelopeBResult) {
          throw new TRPCError({ code: 'NOT_FOUND', message: 'Envelope not found' });
        }

        const cas = new CAS_Bridge();
        await cas.open();
        const mergeOps = new MergeOperations(cas);

        try {
          const result = await mergeOps.mergeEnvelopes(
            ctx.user.id,
            envelopeAResult[0] as any,
            envelopeBResult[0] as any
          );

          // Increment merge count after successful merge
          await incrementMergeCount(ctx.user.id);

          return result;
        } finally {
          await cas.close();
        }
      }),
    checkLimit: protectedProcedure.query(async ({ ctx }) => {
      const { canPerformMerge } = await import('./db');
      return canPerformMerge(ctx.user.id);
    }),
  }),
});

export type AppRouter = typeof appRouter;

