/**
 * Error Tracking Integration
 * Supports Sentry and fallback logging
 */

interface ErrorContext {
  userId?: number;
  envelopeId?: string;
  mergeId?: string;
  action?: string;
  metadata?: Record<string, any>;
}

class ErrorTracker {
  private initialized = false;
  private sentry: any = null;

  /**
   * Initialize error tracking (Sentry)
   */
  async initialize() {
    if (this.initialized) return;

    try {
      // Try to load Sentry if DSN is provided
      if (process.env.SENTRY_DSN) {
        const Sentry = await import('@sentry/nextjs');
        Sentry.init({
          dsn: process.env.SENTRY_DSN,
          environment: process.env.NODE_ENV || 'development',
          tracesSampleRate: process.env.NODE_ENV === 'production' ? 0.1 : 1.0,
          beforeSend(event, hint) {
            // Filter out sensitive data
            if (event.request) {
              delete event.request.cookies;
              delete event.request.headers?.['authorization'];
            }
            return event;
          },
        });
        this.sentry = Sentry;
        this.initialized = true;
        console.log('[Error Tracking] Sentry initialized');
      } else {
        console.warn('[Error Tracking] SENTRY_DSN not set, using console logging');
      }
    } catch (error) {
      console.error('[Error Tracking] Failed to initialize:', error);
    }
  }

  /**
   * Capture an error
   */
  captureError(error: Error, context?: ErrorContext) {
    if (this.sentry) {
      this.sentry.withScope((scope: any) => {
        if (context?.userId) {
          scope.setUser({ id: context.userId.toString() });
        }
        if (context?.envelopeId) {
          scope.setTag('envelope_id', context.envelopeId);
        }
        if (context?.mergeId) {
          scope.setTag('merge_id', context.mergeId);
        }
        if (context?.action) {
          scope.setTag('action', context.action);
        }
        if (context?.metadata) {
          scope.setContext('metadata', context.metadata);
        }
        this.sentry.captureException(error);
      });
    } else {
      // Fallback logging
      console.error('[Error]', {
        message: error.message,
        stack: error.stack,
        context,
      });
    }
  }

  /**
   * Capture a message
   */
  captureMessage(message: string, level: 'info' | 'warning' | 'error' = 'info', context?: ErrorContext) {
    if (this.sentry) {
      this.sentry.withScope((scope: any) => {
        if (context?.userId) {
          scope.setUser({ id: context.userId.toString() });
        }
        if (context?.metadata) {
          scope.setContext('metadata', context.metadata);
        }
        this.sentry.captureMessage(message, level);
      });
    } else {
      console[level === 'error' ? 'error' : level === 'warning' ? 'warn' : 'log']('[Message]', message, context);
