import { createHash, generateKeyPairSync, sign, verify } from 'crypto';
import { nanoid } from 'nanoid';
import { CAS_Bridge } from './cas-bridge';
import { createEnvelope, logAuditEntry } from './db';
import { InsertEnvelope, InsertAuditEntry } from '../drizzle/schema';

/**
 * Envelope: Cryptographically signed DAG of conversation nodes
 */
export interface CE_Envelope {
  id: string;
  userId: number;
  title: string;
  description?: string;
  sourceType: 'chatgpt' | 'claude' | 'manual' | 'merged';
  nodes: EnvelopeNode[];
  edges: EnvelopeEdge[];
  merkleRoot: string;
  signature: {
    algorithm: string;
    publicKey: string;
    hash: string;
    signature: string;
    signedAt: string;
  };
  metadata?: Record<string, any>;
}

export interface EnvelopeNode {
  id: string;
  role: string;
  content: string;
  timestamp: string;
  confidence: number; // 0-100
  parentNodes: string[];
}

export interface EnvelopeEdge {
  from: string;
  to: string;
  type: 'follows' | 'federation' | 'conflict';
  confidence?: number;
}

/**
 * Envelope Operations: Create, sign, verify, and merge envelopes
 */
export class EnvelopeOperations {
  private cas: CAS_Bridge;

  constructor(cas: CAS_Bridge) {
    this.cas = cas;
  }

  /**
   * Create an envelope from chat data
   * Enhanced with error tracking and recovery
   */
  async createEnvelope(
    userId: number,
    title: string,
    nodes: EnvelopeNode[],
    edges: EnvelopeEdge[],
    sourceType: 'chatgpt' | 'claude' | 'manual' = 'manual',
    description?: string
  ): Promise<CE_Envelope> {
    const id = `urn:uuid:${nanoid()}`;
    const merkleRoot = this.computeMerkleRoot(nodes);

    // Generate Ed25519 key pair for signing
    const { privateKey, publicKey } = generateKeyPairSync('ed25519');

    const envelope: CE_Envelope = {
      id,
      userId,
      title,
      description,
      sourceType,
      nodes,
      edges,
      merkleRoot,
      signature: {
        algorithm: 'Ed25519',
        publicKey: publicKey.export({ type: 'spki', format: 'pem' }).toString(),
        hash: '',
        signature: '',
        signedAt: new Date().toISOString(),
      },
    };

    // Sign the envelope
    const canonicalEnvelope = this.canonicalize(envelope);
    const envelopeHash = createHash('sha256').update(canonicalEnvelope).digest('hex');
    const signature = sign(null, Buffer.from(canonicalEnvelope), privateKey).toString('hex');

    envelope.signature.hash = envelopeHash;
    envelope.signature.signature = signature;

    // Store in CAS
    const casData = await this.cas.store(Buffer.from(JSON.stringify(envelope), 'utf-8'));

    // Create database record
    const dbEnvelope: InsertEnvelope = {
      id,
      userId,
      title,
      description,
      sourceType,
      nodeCount: nodes.length,
      edgeCount: edges.length,
      merkleRoot,
      casReference: casData.hash,
      signatureHash: envelopeHash,
      integrityStatus: 'verified',
      confidenceScore: this.computeAverageConfidence(nodes),
      metadata: JSON.stringify({
        casHash: casData.hash,
        publicKey: envelope.signature.publicKey,
      }),
    };

    await createEnvelope(dbEnvelope);

    // Log audit entry
    await logAuditEntry({
      id: `audit_${nanoid()}`,
      userId,
      actionType: 'import',
      resourceType: 'envelope',
      resourceId: id,
      details: JSON.stringify({
        sourceType,
        nodeCount: nodes.length,
        edgeCount: edges.length,
      }),
    });

    return envelope;
  }

  /**
   * Verify envelope integrity
   */
  async verifyEnvelope(envelope: CE_Envelope): Promise<{
    valid: boolean;
    reason?: string;
  }> {
    try {
      // Verify Merkle root
      const computedMerkleRoot = this.computeMerkleRoot(envelope.nodes);
      if (computedMerkleRoot !== envelope.merkleRoot) {
        return { valid: false, reason: 'Merkle root mismatch' };
      }

      // Verify signature
      const canonicalEnvelope = this.canonicalize(envelope);
      const publicKeyPem = envelope.signature.publicKey;
      const signatureBuffer = Buffer.from(envelope.signature.signature, 'hex');

      const isValid = verify(
        null,
        Buffer.from(canonicalEnvelope),
        publicKeyPem,
        signatureBuffer
      );

      if (!isValid) {
        return { valid: false, reason: 'Signature verification failed' };
      }

      return { valid: true };
    } catch (error) {
      return { valid: false, reason: (error as Error).message };
    }
  }

  /**
   * Compute Merkle root from nodes
   */
  private computeMerkleRoot(nodes: EnvelopeNode[]): string {
    if (nodes.length === 0) return createHash('sha256').update('').digest('hex');

    const nodeHashes = nodes.map((node) =>
      createHash('sha256')
        .update(JSON.stringify(node))
        .digest('hex')
    );

    return this.merkleTree(nodeHashes);
  }

  /**
   * Build Merkle tree from hashes
   */
  private merkleTree(hashes: string[]): string {
    if (hashes.length === 0) return '';
    if (hashes.length === 1) return hashes[0];

    const nextLevel: string[] = [];
    for (let i = 0; i < hashes.length; i += 2) {
      const left = hashes[i];
      const right = hashes[i + 1] || hashes[i];
      const combined = createHash('sha256')
        .update(left + right)
        .digest('hex');
      nextLevel.push(combined);
    }

    return this.merkleTree(nextLevel);
  }

  /**
   * Canonicalize envelope for signing (deterministic JSON)
   */
  private canonicalize(envelope: CE_Envelope): string {
    const copy = { ...envelope };
    copy.signature = {
      algorithm: '',
      publicKey: '',
      hash: '',
      signature: '',
      signedAt: '',
    };
    return JSON.stringify(copy, Object.keys(copy).sort());
  }

  /**
   * Compute average confidence across nodes
   */
  private computeAverageConfidence(nodes: EnvelopeNode[]): number {
    if (nodes.length === 0) return 0;
    const sum = nodes.reduce((acc, node) => acc + node.confidence, 0);
    return Math.round(sum / nodes.length);
  }
}

