      const publicKeyPem = envelope.signature.publicKey;
      const signatureBuffer = Buffer.from(envelope.signature.signature, 'hex');

      const isValid = verify(
        null,
        Buffer.from(canonicalEnvelope),
        publicKeyPem,
        signatureBuffer
      );

      if (!isValid) {
        return { valid: false, reason: 'Signature verification failed' };
      }

      return { valid: true };
    } catch (error) {
      return { valid: false, reason: (error as Error).message };
    }
  }

  /**
   * Compute Merkle root from nodes
   */
  private computeMerkleRoot(nodes: EnvelopeNode[]): string {
    if (nodes.length === 0) return createHash('sha256').update('').digest('hex');

    const nodeHashes = nodes.map((node) =>
      createHash('sha256')
        .update(JSON.stringify(node))
        .digest('hex')
    );

    return this.merkleTree(nodeHashes);
  }

  /**
   * Build Merkle tree from hashes
   */
  private merkleTree(hashes: string[]): string {
    if (hashes.length === 0) return '';
    if (hashes.length === 1) return hashes[0];

    const nextLevel: string[] = [];
    for (let i = 0; i < hashes.length; i += 2) {
      const left = hashes[i];
      const right = hashes[i + 1] || hashes[i];
      const combined = createHash('sha256')
        .update(left + right)
        .digest('hex');
      nextLevel.push(combined);
    }

    return this.merkleTree(nextLevel);
  }

  /**
   * Canonicalize envelope for signing (deterministic JSON)
   */
  private canonicalize(envelope: CE_Envelope): string {
    const copy = { ...envelope };
    copy.signature = {
      algorithm: '',
      publicKey: '',
      hash: '',
      signature: '',
      signedAt: '',
    };
    return JSON.stringify(copy, Object.keys(copy).sort());
  }

  /**
   * Compute average confidence across nodes
   */
  private computeAverageConfidence(nodes: EnvelopeNode[]): number {
    if (nodes.length === 0) return 0;
    const sum = nodes.reduce((acc, node) => acc + node.confidence, 0);
    return Math.round(sum / nodes.length);
  }
}

