import React, { useState } from 'react';
import { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle, DialogFooter } from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Card } from '@/components/ui/card';
import { AlertTriangle, CheckCircle, X, ArrowRight, Info } from 'lucide-react';
import { ConflictResolution } from '../merge-ops';

interface ConflictResolutionModalProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  conflicts: ConflictResolution[];
  nodeA: { id: string; content: string; confidence: number; role: string };
  nodeB: { id: string; content: string; confidence: number; role: string };
  onResolve: (resolution: ConflictResolution) => void;
  onDefer: () => void;
  onCancel: () => void;
}

/**
 * Conflict Resolution Modal
 * 
 * This is where epistemic honesty meets user experience.
 * Users can resolve conflicts, defer them, or mark as irreconcilable.
 * This is the "uncertain cognitive space" where value is created.
 */
export function ConflictResolutionModal({
  open,
  onOpenChange,
  conflicts,
  nodeA,
  nodeB,
  onResolve,
  onDefer,
  onCancel,
}: ConflictResolutionModalProps) {
  const [selectedResolution, setSelectedResolution] = useState<ConflictResolution | null>(null);
  const [currentConflictIndex, setCurrentConflictIndex] = useState(0);

  const currentConflict = conflicts[currentConflictIndex];
  const isIrreconcilable = currentConflict?.preferred === 'irreconcilable';
  const isLastConflict = currentConflictIndex === conflicts.length - 1;

  const handleResolve = () => {
    if (selectedResolution) {
      onResolve(selectedResolution);
      if (isLastConflict) {
        onOpenChange(false);
      } else {
        setCurrentConflictIndex(currentConflictIndex + 1);
        setSelectedResolution(null);
      }
    }
  };

  const handleDefer = () => {
    onDefer();
    if (isLastConflict) {
      onOpenChange(false);
    } else {
      setCurrentConflictIndex(currentConflictIndex + 1);
      setSelectedResolution(null);
    }
  };

  const handleSkip = () => {
    // Auto-resolve with backend suggestion
    if (currentConflict) {
      onResolve(currentConflict);
      if (isLastConflict) {
        onOpenChange(false);
      } else {
        setCurrentConflictIndex(currentConflictIndex + 1);
        setSelectedResolution(null);
      }
    }
  };

  if (!currentConflict) {
    return null;
  }

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-4xl max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <div className="flex items-center justify-between">
            <div>
              <DialogTitle className="text-2xl">Resolve Conflict</DialogTitle>
              <DialogDescription className="mt-2">
                Conflict {currentConflictIndex + 1} of {conflicts.length}: Same node ID with different content
              </DialogDescription>
            </div>
            <div className="flex items-center gap-2 text-sm text-muted-foreground">
              <div className={`px-2 py-1 rounded ${
                isIrreconcilable
                  ? 'bg-red-100 dark:bg-red-900 text-red-900 dark:text-red-100'
                  : 'bg-amber-100 dark:bg-amber-900 text-amber-900 dark:text-amber-100'
              }`}>
                {isIrreconcilable ? 'Irreconcilable' : 'Resolvable'}
              </div>
            </div>
          </div>
        </DialogHeader>

        <div className="space-y-6 mt-4">
          {/* Conflict Info */}
          {isIrreconcilable && (
            <Card className="p-4 bg-red-50 dark:bg-red-900/20 border-red-200 dark:border-red-800">
              <div className="flex items-start gap-3">
                <AlertTriangle className="w-5 h-5 text-red-600 dark:text-red-400 flex-shrink-0 mt-0.5" />
                <div>
                  <h4 className="font-semibold text-red-900 dark:text-red-100 mb-1">
                    Irreconcilable Conflict
                  </h4>
                  <p className="text-sm text-red-800 dark:text-red-200">
                    Confidence difference is too small ({Math.abs(nodeA.confidence - nodeB.confidence)}%) 
                    to auto-resolve. You must choose which version to keep or defer the decision.
                  </p>
                </div>
              </div>
            </Card>
          )}

          {/* Node Comparison */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            {/* Node A */}
            <Card className={`p-4 border-2 transition-all ${
              selectedResolution?.preferred === 'A'
                ? 'border-emerald-500 bg-emerald-50 dark:bg-emerald-900/20'
                : 'border-border hover:border-emerald-300 cursor-pointer'
            }`}
            onClick={() => setSelectedResolution({
              ...currentConflict,
              preferred: 'A',
              reason: `User selected version A (confidence: ${nodeA.confidence}%)`,
            })}>
              <div className="flex items-center justify-between mb-3">
                <h3 className="font-semibold">Version A</h3>
                {selectedResolution?.preferred === 'A' && (
                  <CheckCircle className="w-5 h-5 text-emerald-600" />
                )}
              </div>
              <div className="mb-2">
                <div className={`inline-block px-2 py-1 rounded text-xs font-medium ${
                  nodeA.confidence >= 70
                    ? 'bg-emerald-100 text-emerald-900 dark:bg-emerald-900 dark:text-emerald-100'
                    : nodeA.confidence >= 40
                    ? 'bg-amber-100 text-amber-900 dark:bg-amber-900 dark:text-amber-100'
                    : 'bg-red-100 text-red-900 dark:bg-red-900 dark:text-red-100'
                }`}>
                  {nodeA.confidence}% confidence
                </div>
                <span className="ml-2 text-xs text-muted-foreground">{nodeA.role}</span>
              </div>
              <div className="p-3 bg-slate-50 dark:bg-slate-800 rounded-lg text-sm">
                {nodeA.content}
              </div>
            </Card>

            {/* Node B */}
            <Card className={`p-4 border-2 transition-all ${
              selectedResolution?.preferred === 'B'
                ? 'border-emerald-500 bg-emerald-50 dark:bg-emerald-900/20'
                : 'border-border hover:border-emerald-300 cursor-pointer'
            }`}
            onClick={() => setSelectedResolution({
              ...currentConflict,
              preferred: 'B',
              reason: `User selected version B (confidence: ${nodeB.confidence}%)`,
            })}>
              <div className="flex items-center justify-between mb-3">
                <h3 className="font-semibold">Version B</h3>
                {selectedResolution?.preferred === 'B' && (
                  <CheckCircle className="w-5 h-5 text-emerald-600" />
                )}
              </div>
              <div className="mb-2">
                <div className={`inline-block px-2 py-1 rounded text-xs font-medium ${
                  nodeB.confidence >= 70
                    ? 'bg-emerald-100 text-emerald-900 dark:bg-emerald-900 dark:text-emerald-100'
                    : nodeB.confidence >= 40
                    ? 'bg-amber-100 text-amber-900 dark:bg-amber-900 dark:text-amber-100'
                    : 'bg-red-100 text-red-900 dark:bg-red-900 dark:text-red-100'
                }`}>
                  {nodeB.confidence}% confidence
                </div>
                <span className="ml-2 text-xs text-muted-foreground">{nodeB.role}</span>
              </div>
              <div className="p-3 bg-slate-50 dark:bg-slate-800 rounded-lg text-sm">
                {nodeB.content}
              </div>
            </Card>
          </div>

          {/* Auto-Resolution Suggestion */}
          {!isIrreconcilable && currentConflict.preferred !== 'irreconcilable' && (
            <Card className="p-4 bg-slate-50 dark:bg-slate-800 border-slate-200 dark:border-slate-700">
              <div className="flex items-start gap-3">
                <Info className="w-5 h-5 text-slate-600 dark:text-slate-400 flex-shrink-0 mt-0.5" />
                <div className="flex-1">
                  <h4 className="font-semibold text-sm mb-1">Auto-Resolution Suggestion</h4>
                  <p className="text-sm text-muted-foreground mb-2">
                    {currentConflict.reason}
                  </p>
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={handleSkip}
                    className="mt-2"
                  >
                    Accept Suggestion
                  </Button>
                </div>
              </div>
            </Card>
          )}

          {/* Epistemic Honesty Note */}
          <Card className="p-4 bg-amber-50 dark:bg-amber-900/20 border-amber-200 dark:border-amber-800">
            <div className="flex items-start gap-3">
              <Info className="w-5 h-5 text-amber-600 dark:text-amber-400 flex-shrink-0 mt-0.5" />
              <div>
                <h4 className="font-semibold text-sm text-amber-900 dark:text-amber-100 mb-1">
                  Epistemic Honesty
                </h4>
                <p className="text-sm text-amber-800 dark:text-amber-200">
                  Both versions are preserved in the audit trail. Your choice determines which 
                  version appears in the merged graph, but both remain cryptographically verifiable.
                </p>
              </div>
            </div>
          </Card>
        </div>

        <DialogFooter className="flex flex-col sm:flex-row gap-2 sm:gap-0">
          <div className="flex gap-2 flex-1">
            <Button
              variant="outline"
              onClick={onCancel}
            >
              Cancel Merge
            </Button>
            <Button
              variant="outline"
              onClick={handleDefer}
            >
              Defer ({conflicts.length - currentConflictIndex - 1} remaining)
            </Button>
          </div>
          <div className="flex gap-2">
            {selectedResolution && (
              <Button
                onClick={handleResolve}
                className="bg-emerald-600 hover:bg-emerald-700"
              >
                {isLastConflict ? 'Resolve & Complete' : 'Resolve & Continue'}
                <ArrowRight className="w-4 h-4 ml-2" />
              </Button>
            )}
          </div>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

