```typescriptreact
import React, { useState } from 'react';
import { Card } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { ConflictResolutionModal } from './ConflictResolutionModal';
import { AlertTriangle, Zap, CheckCircle, Info } from 'lucide-react';
import { ConflictResolution } from '../merge-ops';

interface MergePreviewProps {
  envelopeA: { id: string; title: string; nodeCount: number; edgeCount: number };
  envelopeB: { id: string; title: string; nodeCount: number; edgeCount: number };
  predictedConflicts: ConflictResolution[];
  predictedConsensusScore: number;
  onConfirm: () => void;
  onCancel: () => void;
}

/**
 * Merge Preview Component
 * Shows predicted merge outcome before execution
 * Allows users to see conflicts and consensus score
 */
export function MergePreview({
  envelopeA,
  envelopeB,
  predictedConflicts,
  predictedConsensusScore,
  onConfirm,
  onCancel,
}: MergePreviewProps) {
  const [showConflictResolution, setShowConflictResolution] = useState(false);
  const [resolvedConflicts, setResolvedConflicts] = useState<ConflictResolution[]>([]);

  const hasConflicts = predictedConflicts.length > 0;
  const hasIrreconcilable = predictedConflicts.some(c => c.preferred === 'irreconcilable');

  return (
    <>
      <Card className="p-6 border-2 border-emerald-200 dark:border-emerald-800">
        <div className="space-y-4">
          <div>
            <h3 className="text-lg font-semibold mb-2">Merge Preview</h3>
            <p className="text-sm text-muted-foreground">
              Review the predicted merge outcome before proceeding
            </p>
          </div>

          {/* Envelope Summary */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <Card className="p-4 bg-slate-50 dark:bg-slate-800">
              <h4 className="font-semibold text-sm mb-2">{envelopeA.title}</h4>
              <div className="text-xs text-muted-foreground space-y-1">
                <div>{envelopeA.nodeCount} nodes</div>
                <div>{envelopeA.edgeCount} edges</div>
              </div>
            </Card>
            <Card className="p-4 bg-slate-50 dark:bg-slate-800">
              <h4 className="font-semibold text-sm mb-2">{envelopeB.title}</h4>
              <div className="text-xs text-muted-foreground space-y-1">
                <div>{envelopeB.nodeCount} nodes</div>
                <div>{envelopeB.edgeCount} edges</div>
              </div>
            </Card>
          </div>

          {/* Predicted Outcome */}
          <div className="space-y-3">
            <div className="flex items-center justify-between p-3 bg-emerald-50 dark:bg-emerald-900/20 rounded-lg">
              <div className="flex items-center gap-2">
                <Zap className="w-5 h-5 text-emerald-600" />
                <span className="font-semibold">Predicted Consensus Score</span>
              </div>
              <div className={`text-2xl font-bold ${
                predictedConsensusScore >= 70
                  ? 'text-emerald-600'
                  : predictedConsensusScore >= 40
                  ? 'text-amber-600'
                  : 'text-red-600'
              }`}>
                {predictedConsensusScore}%
              </div>
            </div>

            {/* Conflicts Warning */}
            {hasConflicts && (
              <Card className={`p-4 border-2 ${
                hasIrreconcilable
                  ? 'border-red-200 dark:border-red-800 bg-red-50 dark:bg-red-900/20'
                  : 'border-amber-200 dark:border-amber-800 bg-amber-50 dark:bg-amber-900/20'
              }`}>
                <div className="flex items-start gap-3">
                  <AlertTriangle className={`w-5 h-5 flex-shrink-0 mt-0.5 ${
                    hasIrreconcilable ? 'text-red-600' : 'text-amber-600'
                  }`} />
                  <div className="flex-1">
                    <h4 className="font-semibold mb-1">
                      {predictedConflicts.length} Conflict{predictedConflicts.length !== 1 ? 's' : ''} Detected
                    </h4>
                    <p className="text-sm text-muted-foreground mb-3">
                      {hasIrreconcilable
                        ? `${predictedConflicts.filter(c => c.preferred === 'irreconcilable').length} irreconcilable conflict(s) require manual resolution.`
                        : 'Some conflicts can be auto-resolved, but you may want to review them.'}
                    </p>
                    <Button
                      variant="outline"
                      size="sm"
                      onClick={() => setShowConflictResolution(true)}
                    >
                      Review Conflicts
                    </Button>
                  </div>
                </div>
              </Card>
            )}

            {/* No Conflicts */}
            {!hasConflicts && (
              <Card className="p-4 border-emerald-200 dark:border-emerald-800 bg-emerald-50 dark:bg-emerald-900/20">
                <div className="flex items-center gap-2">
                  <CheckCircle className="w-5 h-5 text-emerald-600" />
                  <span className="text-sm font-medium">No conflicts detected. Merge should proceed smoothly.</span>
                </div>
              </Card>
            )}
          </div>

          {/* Actions */}
          <div className="flex flex-col sm:flex-row gap-2 pt-4 border-t">
            <Button
              variant="outline"
              onClick={onCancel}
              className="flex-1"
            >
              Cancel
            </Button>
            <Button
              onClick={() => {
                if (hasConflicts && !resolvedConflicts.length) {
                  setShowConflictResolution(true);
                } else {
                  onConfirm();
                }
              }}
              className="flex-1 bg-emerald-600 hover:bg-emerald-700"
            >
              {hasConflicts ? 'Resolve Conflicts & Merge' : 'Confirm Merge'}
            </Button>
          </div>
        </div>
      </Card>

      {/* Conflict Resolution Modal */}
      {showConflictResolution && predictedConflicts.length > 0 && (
        <ConflictResolutionModal
          open={showConflictResolution}
          onOpenChange={setShowConflictResolution}
          conflicts={predictedConflicts}
          nodeA={{
            id: predictedConflicts[0].nodeId,
            content: 'Node A content', // Would come from actual nodes
            confidence: predictedConflicts[0].confidenceA,
            role: 'user',
          }}
          nodeB={{
            id: predictedConflicts[0].nodeId,
            content: 'Node B content', // Would come from actual nodes
            confidence: predictedConflicts[0].confidenceB,
            role: 'assistant',
          }}
          onResolve={(resolution) => {
            setResolvedConflicts([...resolvedConflicts, resolution]);
          }}
          onDefer={() => {
            // Handle deferral
          }}
          onCancel={onCancel}
        />
      )}
    </>
  );
}

