```typescriptreact
import React, { useState } from 'react';
import { Card } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { MergePreview } from './MergePreview';
import { ConflictResolutionModal } from './ConflictResolutionModal';
import { Zap, AlertTriangle, Loader2 } from 'lucide-react';
import { trpc } from '@/lib/trpc';
import { toast } from 'sonner';
import { ConflictResolution } from '../merge-ops';

interface MergeSelectorProps {
  onMergeComplete?: () => void;
}

/**
 * Merge Selector Component
 * Allows users to select two envelopes and preview/execute merge
 */
export function MergeSelector({ onMergeComplete }: MergeSelectorProps) {
  const [selectedA, setSelectedA] = useState<string | null>(null);
  const [selectedB, setSelectedB] = useState<string | null>(null);
  const [showPreview, setShowPreview] = useState(false);
  const [showConflictResolution, setShowConflictResolution] = useState(false);
  const [resolvedConflicts, setResolvedConflicts] = useState<ConflictResolution[]>([]);

  const { data: envelopes, isLoading } = trpc.envelopes.list.useQuery();
  const previewQuery = trpc.merges.preview.useQuery(
    {
      envelopeAId: selectedA!,
      envelopeBId: selectedB!,
    },
    {
      enabled: !!selectedA && !!selectedB && showPreview,
    }
  );

  const mergeMutation = trpc.merges.create.useMutation({
    onSuccess: () => {
      toast.success('Merge completed successfully');
      setSelectedA(null);
      setSelectedB(null);
      setShowPreview(false);
      setResolvedConflicts([]);
      onMergeComplete?.();
    },
    onError: (error) => {
      toast.error(`Merge failed: ${error.message}`);
    },
  });

  const handlePreview = () => {
    if (!selectedA || !selectedB) {
      toast.error('Please select two envelopes to merge');
      return;
    }
    if (selectedA === selectedB) {
      toast.error('Cannot merge an envelope with itself');
      return;
    }
    setShowPreview(true);
  };

  const handleConfirmMerge = () => {
    if (!selectedA || !selectedB) return;

    mergeMutation.mutate({
      envelopeAId: selectedA,
      envelopeBId: selectedB,
      conflictResolutions: resolvedConflicts.length > 0 ? resolvedConflicts : undefined,
    });
  };

  const envelopeA = envelopes?.find((e: any) => e.id === selectedA);
  const envelopeB = envelopes?.find((e: any) => e.id === selectedB);

  return (
    <div className="space-y-4">
      <div>
        <h3 className="text-lg font-semibold mb-2">Select Envelopes to Merge</h3>
        <p className="text-sm text-muted-foreground">
          Choose two envelopes to merge and discover patterns across conversations
        </p>
      </div>

      {/* Envelope Selection */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {/* Envelope A */}
        <Card className="p-4">
          <h4 className="font-semibold text-sm mb-3">Envelope A</h4>
          {isLoading ? (
            <div className="text-sm text-muted-foreground">Loading...</div>
          ) : envelopes && envelopes.length > 0 ? (
            <div className="space-y-2 max-h-64 overflow-y-auto">
              {envelopes.map((envelope: any) => (
                <button
                  key={envelope.id}
                  onClick={() => setSelectedA(envelope.id)}
                  className={`w-full text-left p-3 rounded-lg border transition-all ${
                    selectedA === envelope.id
                      ? 'border-emerald-500 bg-emerald-50 dark:bg-emerald-900/20'
                      : 'border-border hover:border-emerald-300'
                  }`}
                >
                  <div className="font-medium text-sm">{envelope.title}</div>
                  <div className="text-xs text-muted-foreground mt-1">
                    {envelope.nodeCount} nodes • {envelope.edgeCount} edges
                  </div>
                </button>
              ))}
            </div>
          ) : (
            <div className="text-sm text-muted-foreground">No envelopes available</div>
          )}
        </Card>

        {/* Envelope B */}
        <Card className="p-4">
          <h4 className="font-semibold text-sm mb-3">Envelope B</h4>
          {isLoading ? (
            <div className="text-sm text-muted-foreground">Loading...</div>
          ) : envelopes && envelopes.length > 0 ? (
            <div className="space-y-2 max-h-64 overflow-y-auto">
              {envelopes.map((envelope: any) => (
                <button
                  key={envelope.id}
                  onClick={() => setSelectedB(envelope.id)}
                  className={`w-full text-left p-3 rounded-lg border transition-all ${
                    selectedB === envelope.id
                      ? 'border-emerald-500 bg-emerald-50 dark:bg-emerald-900/20'
                      : 'border-border hover:border-emerald-300'
                  }`}
                >
                  <div className="font-medium text-sm">{envelope.title}</div>
                  <div className="text-xs text-muted-foreground mt-1">
                    {envelope.nodeCount} nodes • {envelope.edgeCount} edges
                  </div>
                </button>
              ))}
            </div>
          ) : (
            <div className="text-sm text-muted-foreground">No envelopes available</div>
          )}
        </Card>
      </div>

      {/* Preview Button */}
      {selectedA && selectedB && (
        <div className="flex justify-end">
          <Button
            onClick={handlePreview}
            disabled={selectedA === selectedB}
            className="gap-2"
          >
            <Zap className="w-4 h-4" />
            Preview Merge
          </Button>
        </div>
      )}

      {/* Merge Preview */}
      {showPreview && envelopeA && envelopeB && previewQuery.data && (
        <MergePreview
          envelopeA={{
            id: envelopeA.id,
            title: envelopeA.title,
            nodeCount: envelopeA.nodeCount,
            edgeCount: envelopeA.edgeCount,
          }}
          envelopeB={{
            id: envelopeB.id,
            title: envelopeB.title,
            nodeCount: envelopeB.nodeCount,
            edgeCount: envelopeB.edgeCount,
          }}
          predictedConflicts={previewQuery.data.conflicts}
          predictedConsensusScore={previewQuery.data.predictedConsensusScore}
          onConfirm={() => {
            if (previewQuery.data.conflicts.length > 0 && resolvedConflicts.length === 0) {
              setShowConflictResolution(true);
            } else {
              handleConfirmMerge();
            }
          }}
          onCancel={() => {
            setShowPreview(false);
            setResolvedConflicts([]);
          }}
        />
      )}

      {/* Loading State */}
      {mergeMutation.isPending && (
        <Card className="p-4 bg-amber-50 dark:bg-amber-900/20 border-amber-200 dark:border-amber-800">
          <div className="flex items-center gap-3">
            <Loader2 className="w-5 h-5 text-amber-600 animate-spin" />
            <div>
              <div className="font-semibold">Merging envelopes...</div>
              <div className="text-sm text-muted-foreground">This may take a moment</div>
            </div>
          </div>
        </Card>
      )}
    </div>
  );
}

