```typescriptreact
import React, { useState, useEffect } from 'react';
import { useAuth } from '@/_core/hooks/useAuth';
import DashboardLayout from '@/components/DashboardLayout';
import { FileImporter } from '@/components/FileImporter';
import { DAGVisualization } from '@/components/DAGVisualization';
import { MergeCounter } from '@/components/MergeCounter';
import { OnboardingGuide } from '@/components/OnboardingGuide';
import { MergeSelector } from '@/components/MergeSelector';
import { EnvelopeErrorBoundary, MergeErrorBoundary } from '@/components/ErrorBoundary';
import { Button } from '@/components/ui/button';
import { Card } from '@/components/ui/card';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Plus, Zap, Lock } from 'lucide-react';
import { trpc } from '@/lib/trpc';
import { toast } from 'sonner';

/**
 * CE Ledger Dashboard
 * Main interface for importing chats, viewing envelopes, and managing merges
 */
export default function Dashboard() {
  const { user } = useAuth();
  const [selectedEnvelope, setSelectedEnvelope] = useState<string | null>(null);
  const [showImporter, setShowImporter] = useState(false);
  const [showOnboarding, setShowOnboarding] = useState(false);

  // Show onboarding for new users (check localStorage)
  useEffect(() => {
    const hasSeenOnboarding = localStorage.getItem('ce-ledger-onboarding-seen');
    if (!hasSeenOnboarding && envelopes && envelopes.length === 0) {
      setShowOnboarding(true);
    }
  }, [envelopes]);

  // Fetch user's envelopes
  const { data: envelopes, isLoading: envelopesLoading, refetch: refetchEnvelopes } = trpc.envelopes.list.useQuery();

  // Fetch user's merges
  const { data: merges, isLoading: mergesLoading } = trpc.merges.list.useQuery();

  // Create envelope mutation
  const createEnvelopeMutation = trpc.envelopes.create.useMutation({
    onSuccess: () => {
      toast.success('Envelope created successfully');
      setShowImporter(false);
      refetchEnvelopes();
    },
    onError: (error) => {
      toast.error(`Failed to create envelope: ${error.message}`);
    },
  });

  const handleImport = async (data: any) => {
    await createEnvelopeMutation.mutateAsync(data);
  };

  const selectedEnvelopeData = envelopes?.find((e: any) => e.id === selectedEnvelope);

  const handleOnboardingComplete = () => {
    setShowOnboarding(false);
    localStorage.setItem('ce-ledger-onboarding-seen', 'true');
  };

  return (
    <DashboardLayout>
      {showOnboarding && (
        <div className="mb-6">
          <OnboardingGuide onComplete={handleOnboardingComplete} />
        </div>
      )}
      <div className="space-y-6">
        {/* Header */}
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-3xl font-bold text-foreground">Sovereign Vault</h1>
            <p className="text-muted-foreground mt-1">
              Reclaim your AI mind. Import, merge, and analyze your conversations.
            </p>
          </div>
          <Button
            onClick={() => setShowImporter(!showImporter)}
            className="gap-2"
          >
            <Plus className="w-4 h-4" />
            Import Chat
          </Button>
        </div>

        {/* Import Section */}
        {showImporter && (
          <EnvelopeErrorBoundary>
            <div className="animate-in fade-in slide-in-from-top-2">
              <FileImporter
                onImport={handleImport}
                isLoading={createEnvelopeMutation.isPending}
              />
            </div>
          </EnvelopeErrorBoundary>
        )}

        {/* Main Content Tabs */}
        <Tabs defaultValue="envelopes" className="w-full">
          <TabsList className="grid w-full grid-cols-2">
            <TabsTrigger value="envelopes">
              Envelopes
              {envelopes && <span className="ml-2 text-xs bg-emerald-100 dark:bg-emerald-900 px-2 py-1 rounded">{envelopes.length}</span>}
            </TabsTrigger>
            <TabsTrigger value="merges">
              Merges
              {merges && <span className="ml-2 text-xs bg-amber-100 dark:bg-amber-900 px-2 py-1 rounded">{merges.length}</span>}
            </TabsTrigger>
          </TabsList>

          {/* Envelopes Tab */}
          <TabsContent value="envelopes" className="space-y-4">
            {envelopesLoading ? (
              <Card className="p-8 text-center">
                <p className="text-muted-foreground">Loading envelopes...</p>
              </Card>
            ) : envelopes && envelopes.length > 0 ? (
              <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                {/* Envelope List */}
                <div className="space-y-2">
                  {envelopes.map((envelope: any) => (
                    <Card
                      key={envelope.id}
                      className={`p-4 cursor-pointer transition-all hover:shadow-md ${
                        selectedEnvelope === envelope.id
                          ? 'ring-2 ring-emerald-500 bg-emerald-50 dark:bg-emerald-900/20'
                          : ''
                      }`}
                      onClick={() => setSelectedEnvelope(envelope.id)}
                    >
                      <div className="flex items-start justify-between gap-2">
                        <div className="flex-1 min-w-0">
                          <h3 className="font-semibold text-sm truncate">{envelope.title}</h3>
                          <p className="text-xs text-muted-foreground mt-1">
                            {envelope.nodeCount} nodes • {envelope.edgeCount} edges
                          </p>
                        </div>
                        <div className={`px-2 py-1 rounded text-xs font-medium ${
                          envelope.confidenceScore >= 70
                            ? 'heatmap-high'
                            : envelope.confidenceScore >= 40
                            ? 'heatmap-medium'
                            : 'heatmap-low'
                        }`}>
                          {envelope.confidenceScore}%
                        </div>
                      </div>
                      <div className="flex items-center gap-1 mt-2 text-xs text-muted-foreground">
                        {envelope.integrityStatus === 'verified' && (
                          <>
                            <Lock className="w-3 h-3 text-emerald-600" />
                            <span>Verified</span>
                          </>
                        )}
                      </div>
                    </Card>
                  ))}
                </div>

                {/* DAG Visualization */}
                {selectedEnvelopeData && (
                  <div className="lg:col-span-2 h-96">
                    <Card className="p-4 bg-slate-50 dark:bg-slate-800 h-full flex items-center justify-center">
                      <p className="text-muted-foreground text-center">
                        DAG visualization for {selectedEnvelopeData.title} ({selectedEnvelopeData.nodeCount} nodes)
                      </p>
                    </Card>
                  </div>
                )}
              </div>
            ) : (
              <Card className="p-8 text-center">
                <p className="text-muted-foreground mb-4">No envelopes yet. Import your first chat to get started.</p>
                <Button onClick={() => setShowImporter(true)} variant="outline">
                  Import Chat
                </Button>
              </Card>
            )}
          </TabsContent>

          {/* Merges Tab */}
          <TabsContent value="merges" className="space-y-4">
            {mergesLoading ? (
              <Card className="p-8 text-center">
                <p className="text-muted-foreground">Loading merges...</p>
              </Card>
            ) : merges && merges.length > 0 ? (
              <div className="space-y-3">
                {merges.map((merge: any) => (
                  <Card key={merge.id} className="p-4">
                    <div className="flex items-start justify-between">
                      <div>
                        <h3 className="font-semibold text-sm">Merge #{merge.id.substring(0, 8)}</h3>
                        <p className="text-xs text-muted-foreground mt-1">
                          {merge.nodesMerged} nodes • {merge.edgesMerged} edges merged
                        </p>
                      </div>
                      <div className={`px-3 py-1 rounded text-sm font-medium ${
                        merge.consensusScore >= 70
                          ? 'heatmap-high'
                          : merge.consensusScore >= 40
                          ? 'heatmap-medium'
                          : 'heatmap-low'
                      }`}>
                        {merge.consensusScore}% consensus
                      </div>
                    </div>
                  </Card>
                ))}
              </div>
            ) : (
              <Card className="p-8 text-center">
                <Zap className="w-8 h-8 text-amber-500 mx-auto mb-2" />
                <p className="text-muted-foreground mb-4">No merges yet. Import multiple chats and merge them to discover patterns.</p>
                <Button onClick={() => setShowImporter(true)} variant="outline">
                  Import Chat
                </Button>
              </Card>
            )}
          </TabsContent>
        </Tabs>

        {/* Merge Counter Component */}
        <MergeCounter />
      </div>
    </DashboardLayout>
  );
}

