                  confidenceB: nodeB.confidence,
                };

          conflicts.push(resolution);
        }
      }
    });

    return conflicts;
  }

  /**
   * Merge nodes in batches for large envelopes (prevents LevelDB bloat)
   */
  private async mergeNodesBatched(
    nodesA: EnvelopeNode[],
    nodesB: EnvelopeNode[],
    batchSize: number
  ): Promise<EnvelopeNode[]> {
    const nodeMap = new Map<string, EnvelopeNode>();
    const allNodes = [...nodesA, ...nodesB];

    // Process in batches
    for (let i = 0; i < allNodes.length; i += batchSize) {
      const batch = allNodes.slice(i, i + batchSize);

      batch.forEach((node) => {
        if (nodeMap.has(node.id)) {
          const existing = nodeMap.get(node.id)!;
          // Average confidences
          existing.confidence = Math.round((existing.confidence + node.confidence) / 2);
          // Merge parent nodes
          existing.parentNodes = Array.from(
            new Set([...existing.parentNodes, ...node.parentNodes])
          );
        } else {
          nodeMap.set(node.id, { ...node });
        }
      });

      // Yield to event loop to prevent blocking
      await new Promise(resolve => setImmediate(resolve));
    }

    return Array.from(nodeMap.values());
  }

  /**
   * Compute consensus score based on merged nodes and conflicts
   */
  private computeConsensusScore(
    nodes: EnvelopeNode[],
    conflicts: ConflictResolution[]
  ): number {
    if (nodes.length === 0) return 0;

    const avgConfidence = nodes.reduce((sum, n) => sum + n.confidence, 0) / nodes.length;
    const conflictPenalty = (conflicts.length / nodes.length) * 20; // Up to 20% penalty

    return Math.max(0, Math.round(avgConfidence - conflictPenalty));
  }
}

