   * Public for preview functionality
   */
  detectConflicts(
    nodesA: EnvelopeNode[],
    nodesB: EnvelopeNode[]
  ): ConflictResolution[] {
    const conflicts: ConflictResolution[] = [];
    const nodeMapB = new Map(nodesB.map((n) => [n.id, n]));

    nodesA.forEach((nodeA) => {
      const nodeB = nodeMapB.get(nodeA.id);
      if (nodeB && nodeA.content !== nodeB.content) {
        const confidenceDiff = Math.abs(nodeA.confidence - nodeB.confidence);

        // If confidence difference is very small (< 5%), mark as irreconcilable
        if (confidenceDiff < 5) {
          conflicts.push({
            nodeId: nodeA.id,
            preferred: 'irreconcilable',
            reason: 'Confidence difference too small to auto-resolve',
            confidenceA: nodeA.confidence,
            confidenceB: nodeB.confidence,
          });
        } else {
          // Confidence-based conflict resolution: prefer higher confidence
          const resolution: ConflictResolution =
            nodeA.confidence >= nodeB.confidence
              ? {
                  nodeId: nodeA.id,
                  preferred: 'A',
                  reason: `Higher confidence in A (${nodeA.confidence}% vs ${nodeB.confidence}%)`,
                  confidenceA: nodeA.confidence,
                  confidenceB: nodeB.confidence,
                }
              : {
                  nodeId: nodeB.id,
                  preferred: 'B',
                  reason: `Higher confidence in B (${nodeB.confidence}% vs ${nodeA.confidence}%)`,
                  confidenceA: nodeA.confidence,
                  confidenceB: nodeB.confidence,
                };

          conflicts.push(resolution);
        }
      }
    });

    return conflicts;
  }

  /**
