import { COOKIE_NAME } from "@shared/const";
import { getSessionCookieOptions } from "./_core/cookies";
import { systemRouter } from "./_core/systemRouter";
import { publicProcedure, protectedProcedure, router } from "./_core/trpc";
import { TRPCError } from "@trpc/server";
import { z } from "zod";

export const appRouter = router({
    // if you need to use socket.io, read and register route in server/_core/index.ts, all api should start with '/api/' so that the gateway can route correctly
  system: systemRouter,
  subscription: router({
    createCheckout: protectedProcedure
      .input(z.object({
        priceId: z.string(),
      }))
      .mutation(async ({ ctx, input }) => {
        const { createCheckoutSession } = await import('./stripe-handler');
        const origin = ctx.req.headers.origin || 'http://localhost:3000';
        const url = await createCheckoutSession(
          ctx.user.id,
          ctx.user.email || '',
          ctx.user.name || 'User',
          input.priceId,
          origin as string
        );
        return { url };
      }),
    status: protectedProcedure.query(async ({ ctx }) => {
      const { getSubscriptionStatus } = await import('./stripe-handler');
      return getSubscriptionStatus(ctx.user.id);
    }),
  }),
  auth: router({
    me: publicProcedure.query(opts => opts.ctx.user),
    logout: publicProcedure.mutation(({ ctx }) => {
      const cookieOptions = getSessionCookieOptions(ctx.req);
      ctx.res.clearCookie(COOKIE_NAME, { ...cookieOptions, maxAge: -1 });
      return {
        success: true,
      } as const;
    }),
  }),

  envelopes: router({
    list: protectedProcedure.query(async ({ ctx }) => {
      const { getEnvelopesByUser } = await import('./db');
      return getEnvelopesByUser(ctx.user.id);
    }),
    create: protectedProcedure
      .input(z.object({
        title: z.string(),
        description: z.string().optional(),
        nodes: z.array(z.object({
          id: z.string(),
          role: z.string(),
          content: z.string(),
          timestamp: z.string(),
          confidence: z.number(),
          parentNodes: z.array(z.string()),
        })),
        edges: z.array(z.object({
          from: z.string(),
          to: z.string(),
          type: z.enum(['follows', 'federation', 'conflict']),
          confidence: z.number().optional(),
        })),
        sourceType: z.enum(['chatgpt', 'claude', 'manual']),
      }))
      .mutation(async ({ ctx, input }) => {
        const { EnvelopeOperations } = await import('./envelope-ops');
        const { CAS_Bridge } = await import('./cas-bridge');
        const cas = new CAS_Bridge();
        await cas.open();
        const envelopeOps = new EnvelopeOperations(cas);
        const envelope = await envelopeOps.createEnvelope(
          ctx.user.id,
          input.title,
          input.nodes,
          input.edges,
          input.sourceType,
          input.description
        );
        await cas.close();
        return envelope;
      }),
  }),
  merges: router({
    list: protectedProcedure.query(async ({ ctx }) => {
      const { getMergesByUser } = await import('./db');
      return getMergesByUser(ctx.user.id);
    }),
    preview: protectedProcedure
      .input(z.object({
        envelopeAId: z.string(),
        envelopeBId: z.string(),
      }))
      .query(async ({ ctx, input }) => {
        const { getEnvelopeById } = await import('./db');
        const { MergeOperations } = await import('./merge-ops');
        const { CAS_Bridge } = await import('./cas-bridge');

        const envelopeAResult = await getEnvelopeById(input.envelopeAId);
        const envelopeBResult = await getEnvelopeById(input.envelopeBId);

        if (!envelopeAResult || !envelopeBResult) {
          throw new TRPCError({ code: 'NOT_FOUND', message: 'Envelope not found' });
        }

        const envelopeA = envelopeAResult[0] as any;
        const envelopeB = envelopeBResult[0] as any;

        // Detect conflicts without merging
        const cas = new CAS_Bridge();
        await cas.open();
        const mergeOps = new MergeOperations(cas);

        const conflicts = mergeOps.detectConflicts(envelopeA.nodes, envelopeB.nodes);

        // Predict consensus score
        const mergedNodes = mergeOps.mergeNodes(envelopeA.nodes, envelopeB.nodes);
        const predictedScore = mergeOps.computeConsensusScore(mergedNodes, conflicts);

        // Get conflict node details for UI
        const conflictDetails = conflicts.map(conflict => {
          const nodeA = envelopeA.nodes.find(n => n.id === conflict.nodeId);
          const nodeB = envelopeB.nodes.find(n => n.id === conflict.nodeId);
          return {
            conflict,
            nodeA: nodeA ? {
              id: nodeA.id,
              content: nodeA.content,
              confidence: nodeA.confidence,
              role: nodeA.role,
            } : null,
            nodeB: nodeB ? {
              id: nodeB.id,
              content: nodeB.content,
              confidence: nodeB.confidence,
              role: nodeB.role,
            } : null,
          };
        });

        await cas.close();

        return {
          conflicts,
          conflictDetails,
          predictedConsensusScore: predictedScore,
          predictedNodeCount: mergedNodes.length,
          predictedEdgeCount: envelopeA.edges.length + envelopeB.edges.length + 1, // +1 for federation edge
        };
      }),
    create: protectedProcedure
      .input(z.object({
        envelopeAId: z.string(),
        envelopeBId: z.string(),
        conflictResolutions: z.array(z.object({
          nodeId: z.string(),
          preferred: z.enum(['A', 'B', 'deferred', 'irreconcilable']),
          reason: z.string(),
          confidenceA: z.number(),
          confidenceB: z.number(),
        })).optional(),
      }))
      .mutation(async ({ ctx, input }) => {
        const { getEnvelopeById, canPerformMerge, incrementMergeCount } = await import('./db');
        const { MergeOperations } = await import('./merge-ops');
        const { CAS_Bridge } = await import('./cas-bridge');

        // Freemium gate: Check if user can perform merge
        const mergeCheck = await canPerformMerge(ctx.user.id);
        if (!mergeCheck.allowed) {
          throw new TRPCError({ 
            code: 'FORBIDDEN', 
            message: `Merge limit reached. You have ${mergeCheck.mergesRemaining} merges remaining this month. Upgrade to Premium for unlimited merges.` 
          });
        }

        const envelopeAResult = await getEnvelopeById(input.envelopeAId);
        const envelopeBResult = await getEnvelopeById(input.envelopeBId);

        if (!envelopeAResult || !envelopeBResult) {
          throw new TRPCError({ code: 'NOT_FOUND', message: 'Envelope not found' });
        }

        const envelopeA = envelopeAResult[0] as any;
        const envelopeB = envelopeBResult[0] as any;

        const cas = new CAS_Bridge();
        await cas.open();
        const mergeOps = new MergeOperations(cas);

        try {
          // Apply user conflict resolutions if provided
          if (input.conflictResolutions && input.conflictResolutions.length > 0) {
            // This would modify the merge behavior based on user resolutions
            // For now, we proceed with standard merge
          }

          const result = await mergeOps.mergeEnvelopes(
            ctx.user.id,
            envelopeA,
            envelopeB
          );

          // Increment merge count after successful merge
          await incrementMergeCount(ctx.user.id);

          return result;
        } finally {
          await cas.close();
        }
      }),
    checkLimit: protectedProcedure.query(async ({ ctx }) => {
      const { canPerformMerge } = await import('./db');
      return canPerformMerge(ctx.user.id);
    }),
  }),
});

export type AppRouter = typeof appRouter;

