              </Card>
            )}
          </div>

          {/* Actions */}
          <div className="flex flex-col sm:flex-row gap-2 pt-4 border-t">
            <Button
              variant="outline"
              onClick={onCancel}
              className="flex-1"
            >
              Cancel
            </Button>
            <Button
              onClick={() => {
                if (hasConflicts && !resolvedConflicts.length) {
                  setShowConflictResolution(true);
                } else {
                  onConfirm();
                }
              }}
              className="flex-1 bg-emerald-600 hover:bg-emerald-700"
            >
              {hasConflicts ? 'Resolve Conflicts & Merge' : 'Confirm Merge'}
            </Button>
          </div>
        </div>
      </Card>

      {/* Conflict Resolution Modal */}
      {showConflictResolution && predictedConflicts.length > 0 && (
        <ConflictResolutionModal
          open={showConflictResolution}
          onOpenChange={setShowConflictResolution}
          conflicts={predictedConflicts}
          nodeA={{
            id: predictedConflicts[0].nodeId,
            content: 'Node A content', // Would come from actual nodes
            confidence: predictedConflicts[0].confidenceA,
            role: 'user',
          }}
          nodeB={{
            id: predictedConflicts[0].nodeId,
            content: 'Node B content', // Would come from actual nodes
            confidence: predictedConflicts[0].confidenceB,
