          }}
          onResolve={(resolution) => {
            setResolvedConflicts([...resolvedConflicts, resolution]);
          }}
          onDefer={() => {
            // Handle deferral
          }}
          onCancel={onCancel}
        />
      )}
    </>
  );
}

