    // packages/anchoring-engine/src/index.ts
    import { EvidenceBlock, CERole, ConversationDAG, AnchorHypothesis, ResolvedAnchors } from '@ce/schema';

    /**
     * THE MISSING TRANSDUCER
     * Converts spatial evidence to temporal DAG nodes
     */
    export class AnchoringEngine {
      private readonly SIGNAL_WEIGHTS = {
        TEXTUAL_CONTINUITY: 0.35,
        SPATIAL_FLOW: 0.30,
        TEMPORAL_MARKERS: 0.20,
        LAYOUT_HEURISTICS: 0.15
      };

      /**
       * Phase 1: Generate anchor hypotheses from evidence
       */
      generateHypotheses(evidenceBlocks: EvidenceBlock[]): AnchorHypothesis[] {
        const hypotheses: AnchorHypothesis[] = [];

        for (const evidence of evidenceBlocks) {
          // Each evidence block can generate multiple hypotheses
          const evidenceHypotheses = this.generateHypothesesForEvidence(evidence);
          hypotheses.push(...evidenceHypotheses);
        }

        return this.applyOcclusionPenalties(hypotheses);
      }

      /**
       * Phase 2: Resolve conflicts between competing hypotheses
       */
      resolveConflicts(hypotheses: AnchorHypothesis[]): ResolvedAnchors {
        // 1. Group by temporal position (±0.1 threshold)
        const temporalGroups = this.groupByTemporalPosition(hypotheses);

        const resolved: ResolvedAnchors = {
          anchors: [],
          conflicts: [],
          gaps: []
        };

        // 2. Resolve each group
        for (const group of temporalGroups) {
          if (group.length === 1) {
            // No conflict
            resolved.anchors.push(this.createResolvedAnchor(group[0]));
          } else {
            // Conflict detected
            const conflictResolution = this.resolveGroupConflict(group);
            resolved.anchors.push(conflictResolution.anchor);
            if (conflictResolution.conflict) {
              resolved.conflicts.push(conflictResolution.conflict);
            }
          }
        }

        // 3. Detect temporal gaps
        resolved.gaps = this.detectTemporalGaps(resolved.anchors);

        return resolved;
      }

      /**
       * Phase 3: Construct DAG from resolved anchors
       */
      constructDAG(anchors: ResolvedAnchors, existingDAG?: ConversationDAG): ConversationDAG {
        const dag: ConversationDAG = existingDAG || {
          nodes: [],
          edges: []
        };

        // Sort anchors by temporal position
        const sortedAnchors = [...anchors.anchors].sort((a, b) => 
          a.temporal_position - b.temporal_position
        );

        // Create nodes
        for (let i = 0; i < sortedAnchors.length; i++) {
          const anchor = sortedAnchors[i];

          // Check if node already exists
          const existingNode = this.findExistingNode(dag, anchor);

          if (existingNode) {
            // Update existing node with new belief layer
            this.updateNodeWithAnchor(existingNode, anchor);
          } else {
            // Create new node
            const newNode = this.createNodeFromAnchor(anchor, i + 1);
            dag.nodes.push(newNode);

            // Create edges
            if (i > 0) {
              const parentNode = this.determineParentNode(dag, newNode, sortedAnchors[i - 1]);
              if (parentNode) {
                dag.edges.push({
                  from: parentNode.node_id,
                  to: newNode.node_id,
                  type: this.determineEdgeType(parentNode, newNode)
                });
              }
            }
          }
        }

        // Insert gap nodes
        for (const gap of anchors.gaps) {
          const gapNode = this.createGapNode(gap);
          dag.nodes.push(gapNode);

          // Connect gap to surrounding nodes
          if (gap.after_node) {
            dag.edges.push({
              from: gap.after_node,
              to: gapNode.node_id,
              type: 'follows_from'
            });
          }
        }

        // Validate DAG invariants
        this.validateDAG(dag);

        return dag;
      }

      /**
       * Core transduction: Evidence → Hypothesis
       */
      private generateHypothesesForEvidence(evidence: EvidenceBlock): AnchorHypothesis[] {
        const hypotheses: AnchorHypothesis[] = [];

        // Extract text content for semantic analysis
        const textContent = this.extractTextContent(evidence);

        // Generate temporal position hypotheses
        const temporalPositions = this.generateTemporalPositions(evidence);

        // Generate role hypotheses
        const roleCandidates = this.generateRoleCandidates(evidence);

        // Combine possibilities
        for (const tempPos of temporalPositions) {
          for (const role of roleCandidates) {
            const confidence = this.computeHypothesisConfidence(evidence, tempPos, role);

            hypotheses.push({
              evidence_id: evidence.id,
              temporal_position: tempPos.position,
              temporal_confidence: tempPos.confidence,
              proposed_role: role.role,
              role_confidence: role.confidence,
              spatial_signals: this.extractSpatialSignals(evidence),
              temporal_signals: this.extractTemporalSignals(evidence),
              textual_signals: this.extractTextualSignals(evidence, textContent),
              overall_confidence: confidence
            });
          }
        }

        return hypotheses;
      }

      /**
       * Confidence computation (weighted signals)
       */
      private computeHypothesisConfidence(
        evidence: EvidenceBlock, 
        temporal: {position: number, confidence: number},
        role: {role: CERole, confidence: number}
      ): number {
        const signals = {
          spatial: this.computeSpatialSignal(evidence),
          textual: this.computeTextualSignal(evidence),
          temporal: temporal.confidence,
          layout: this.computeLayoutSignal(evidence)
        };

        const weightedSum = 
          signals.spatial * this.SIGNAL_WEIGHTS.SPATIAL_FLOW +
          signals.textual * this.SIGNAL_WEIGHTS.TEXTUAL_CONTINUITY +
          signals.temporal * this.SIGNAL_WEIGHTS.TEMPORAL_MARKERS +
          signals.layout * this.SIGNAL_WEIGHTS.LAYOUT_HEURISTICS;

        // Apply degradation factor
        const degradation = this.getDegradationFactor(evidence.occlusion_state);

        return weightedSum * degradation;
      }

      private getDegradationFactor(occlusionState: string): number {
        const factors: Record<string, number> = {
          'none': 1.0,
          'keyboard': 0.7,
          'partial': 0.5,
          'other': 0.3
        };
        return factors[occlusionState] || 0.5;
      }

      /**
       * Gap detection algorithm
       */
      private detectTemporalGaps(anchors: ResolvedAnchor[]): TemporalGap[] {
        const gaps: TemporalGap[] = [];
        const sorted = [...anchors].sort((a, b) => a.temporal_position - b.temporal_position);

        const AVG_TURN_LENGTH = 1.0; // Normalized temporal units
        const GAP_THRESHOLD = 2.0 * AVG_TURN_LENGTH;

        for (let i = 0; i < sorted.length - 1; i++) {
          const current = sorted[i];
          const next = sorted[i + 1];
          const gapSize = next.temporal_position - current.temporal_position;

          if (gapSize > GAP_THRESHOLD) {
            const estimatedTurns = Math.floor(gapSize / AVG_TURN_LENGTH);

            gaps.push({
              after_node: current.node_id,
              before_node: next.node_id,
              estimated_gap_size: gapSize,
              estimated_missing_turns: estimatedTurns,
              confidence: this.computeGapConfidence(gapSize)
            });
          }
        }

        return gaps;
      }

      private computeGapConfidence(gapSize: number): number {
        // Confidence decreases for very large gaps (more uncertainty)
        const MAX_GAP = 10.0;
        return Math.max(0.1, 1.0 - (gapSize / MAX_GAP));
      }
    }

