// packages/epistemic-calculus/src/propagation.ts
    export class EpistemicEngine {
      // Constants from the Epistemic Calculus
      private readonly SIGNAL_WEIGHTS = {
        TEXTUAL: 0.35,
        SPATIAL: 0.30,
        TEMPORAL: 0.20,
        LAYOUT: 0.15
      };

      private readonly OCCLUSION_PENALTIES = {
        none: 1.0,
        keyboard: 0.7,
        partial: 0.5,
        other: 0.3
      };

      private readonly TRANSDUCTION_EFFICIENCY = {
        api_direct: 1.00,
        dom_scrape: 0.95,
        ocr_high_res: 0.85,
        ocr_low_res: 0.60,
        manual_transcription: 0.50
      };

      private readonly PROPAGATION_FACTORS = {
        response_to: 0.99,     // Direct causality
        follows_from: 0.95,    // Temporal sequence
        branch_of: 0.90,       // Parallel reality penalty
        inferred_next: 0.50    // Epistemic break
      };

      /**
       * AXIOM 1: The Decay Equation
       * C_node = C_evidence × T_transduction × δ(C_parent)
       */
      computeNodeConfidence(
        evidenceConfidence: number,
        transductionMethod: keyof typeof this.TRANSDUCTION_EFFICIENCY,
        parentConfidence: number | null,
        edgeType: keyof typeof this.PROPAGATION_FACTORS
      ): number {
        // Base confidence from evidence
        let C_node = evidenceConfidence * this.TRANSDUCTION_EFFICIENCY[transductionMethod];

        // Apply parent propagation if exists
        if (parentConfidence !== null) {
          const δ = this.PROPAGATION_FACTORS[edgeType];
          C_node *= (parentConfidence * δ);
        }

        return Math.min(1.0, Math.max(0.0, C_node));
      }

      /**
       * AXIOM 2: Evidence Confidence
       * C_evidence = min(1.0, Σ(w_i × s_i) × P_occlusion)
       */
      computeEvidenceConfidence(
        signals: {
          textual: number;    // s_textual ∈ [0,1]
          spatial: number;    // s_spatial ∈ [0,1]
          temporal: number;   // s_temporal ∈ [0,1]
          layout: number;     // s_layout ∈ [0,1]
        },
        occlusionState: keyof typeof this.OCCLUSION_PENALTIES
      ): number {
        const weightedSum = 
          signals.textual * this.SIGNAL_WEIGHTS.TEXTUAL +
          signals.spatial * this.SIGNAL_WEIGHTS.SPATIAL +
          signals.temporal * this.SIGNAL_WEIGHTS.TEMPORAL +
          signals.layout * this.SIGNAL_WEIGHTS.LAYOUT;

        const occlusionPenalty = this.OCCLUSION_PENALTIES[occlusionState];

        return Math.min(1.0, weightedSum * occlusionPenalty);
      }

      /**
       * AXIOM 5: Bayesian Conflict Resolution
       * P(Role_A | E1, E2) = [P(E2 | Role_A) × P(Role_A | E1)] / P(E2)
       */
      resolveConflictingEvidence(
        priorBelief: { role: string; confidence: number },
        newEvidence: { role: string; confidence: number }
      ): { role: string; confidence: number; state: 'conflict' | 'resolved' } {
        // If roles agree, combine confidences
        if (priorBelief.role === newEvidence.role) {
          const combinedConfidence = 1 - (1 - priorBelief.confidence) * (1 - newEvidence.confidence);
          return {
            role: priorBelief.role,
            confidence: combinedConfidence,
            state: 'resolved'
          };
        }

        // Bayesian update for conflicting roles
        const P_E2_given_RoleA = newEvidence.role === priorBelief.role ? 
          newEvidence.confidence : 
          (1 - newEvidence.confidence);

        const P_RoleA_given_E1 = priorBelief.confidence;
        const P_E2 = 0.5; // Uniform prior assumption

        const posterior = (P_E2_given_RoleA * P_RoleA_given_E1) / P_E2;

        // Check if posterior is significantly different
        if (Math.abs(posterior - 0.5) > 0.3) {
          return {
            role: posterior > 0.5 ? priorBelief.role : newEvidence.role,
            confidence: Math.max(posterior, 1 - posterior),
            state: 'resolved'
          };
        }

        // Otherwise, remain in conflict
        return {
          role: 'unknown',
          confidence: Math.max(priorBelief.confidence, newEvidence.confidence) * 0.7,
          state: 'conflict'
        };
      }

      /**
       * AXIOM 6: Merkle Integrity Proof
       * H_root = SHA256(H_provenance + H_content_root)
       */
      computeIntegrityHash(envelope: PartialCEEnvelope): string {
        // Canonicalize and hash provenance
        const provenanceHash = this.hashCanonicalJSON(envelope.provenance);

        // Build Merkle tree of nodes
        const nodeHashes = envelope.content.graph_representation.nodes
          .map(node => this.hashNode(node))
          .sort(); // Deterministic ordering

        const contentRoot = this.merkleRoot(nodeHashes);

        // Combine
        const combined = provenanceHash + contentRoot;
        return this.sha256(combined);
      }

      private merkleRoot(hashes: string[]): string {
        if (hashes.length === 0) return this.sha256('');
        if (hashes.length === 1) return hashes[0];

        const newLevel: string[] = [];
        for (let i = 0; i < hashes.length; i += 2) {
          const left = hashes[i];
          const right = i + 1 < hashes.length ? hashes[i + 1] : left;
          newLevel.push(this.sha256(left + right));
        }

        return this.merkleRoot(newLevel);
      }

      /**
       * The User Trump Card: Override with confidence 1.0
       * But reset downstream propagation factors
       */
      applyUserOverride(
        node: CENode,
        userRole: CERole,
        userConfidence: number = 1.0
      ): CENode {
        return {
          ...node,
          attribution: {
            layers: [
              ...node.attribution.layers,
              {
                source: 'user:declarative',
                role: userRole,
                confidence: userConfidence,
                justification: ['user_override'],
                timestamp: new Date().toISOString(),
                state: 'active_override'
              }
            ],
            resolution_summary: {
              active_role: userRole,
              consensus_state: 'user_override'
            }
          }
        };
      }
    }

