    export class EpistemicAnchoringEngine extends AnchoringEngine {
      private epistemic = new EpistemicEngine();

      protected computeHypothesisConfidence(
        evidence: EvidenceBlock,
        temporal: { position: number; confidence: number },
        role: { role: CERole; confidence: number }
      ): number {
        // Use Epistemic Calculus for confidence computation
        const signals = this.extractAllSignals(evidence);

        const C_evidence = this.epistemic.computeEvidenceConfidence(
          {
            textual: signals.textual,
            spatial: signals.spatial,
            temporal: signals.temporal,
            layout: signals.layout
          },
          evidence.occlusion_state
        );

        // Get transduction efficiency from capture method
        const captureMethod = this.detectCaptureMethod(evidence);
        const T_transduction = this.epistemic.TRANSDUCTION_EFFICIENCY[captureMethod];

        // For hypothesis generation, parent confidence is unknown
        // Use temporal confidence as proxy for δ factor
        const δ = temporal.confidence; // Simplified for hypothesis stage

        return C_evidence * T_transduction * δ;
      }

      protected resolveGroupConflict(group: AnchorHypothesis[]): ConflictResolution {
        if (group.length === 1) {
          return { anchor: this.createResolvedAnchor(group[0]), conflict: null };
        }

        // Sort by confidence
        const sorted = [...group].sort((a, b) => b.overall_confidence - a.overall_confidence);

        // Try Bayesian resolution for top two conflicting hypotheses
        const hypothesis1 = sorted[0];
        const hypothesis2 = sorted[1];

        const resolution = this.epistemic.resolveConflictingEvidence(
          { role: hypothesis1.proposed_role, confidence: hypothesis1.overall_confidence },
          { role: hypothesis2.proposed_role, confidence: hypothesis2.overall_confidence }
        );

        if (resolution.state === 'resolved') {
          // Use the resolved role and confidence
          const resolvedAnchor = this.createResolvedAnchor({
            ...hypothesis1,
            proposed_role: resolution.role as CERole,
            overall_confidence: resolution.confidence
          });

          return {
            anchor: resolvedAnchor,
            conflict: {
              type: 'resolved_bayesian',
              hypotheses_involved: [hypothesis1.evidence_id, hypothesis2.evidence_id],
              posterior_probability: resolution.confidence
            }
          };
        } else {
          // Unresolvable conflict
          return {
            anchor: this.createUnknownNodeAnchor(group),
            conflict: {
              type: 'irreconcilable',
              hypotheses_involved: group.map(h => h.evidence_id),
              confidence_delta: Math.abs(hypothesis1.overall_confidence - hypothesis2.overall_confidence)
            }
          };
        }
      }
    }

