    export class CEEpistemicPipeline {
      private anchoring = new EpistemicAnchoringEngine();
      private epistemic = new EpistemicEngine();

      async processConversation(evidenceBlocks: EvidenceBlock[]): Promise<CEEnvelope> {
        // Phase 1: Generate hypotheses with epistemic confidence
        const hypotheses = this.anchoring.generateHypotheses(evidenceBlocks);

        // Phase 2: Resolve conflicts using Bayesian reasoning
        const resolved = this.anchoring.resolveConflicts(hypotheses);

        // Phase 3: Construct initial DAG
        let dag = this.anchoring.constructDAG(resolved);

        // Phase 4: Propagate confidence through DAG
        dag = this.propagateConfidenceThroughDAG(dag);

        // Phase 5: Compute integrity proof
        const integrityHash = this.epistemic.computeIntegrityHash({ 
          provenance: this.createProvenance(evidenceBlocks),
          content: { graph_representation: dag }
        });

        return {
          '@context': 'https://schema.conversation-envelope.org/v1.0',
          id: `urn:uuid:${crypto.randomUUID()}`,
          provenance: {
            ...this.createProvenance(evidenceBlocks),
            fidelity_score: this.computeOverallFidelity(dag),
            integrity_hash: integrityHash
          },
          content: {
            graph_representation: dag
          }
        };
      }

      private propagateConfidenceThroughDAG(dag: ConversationDAG): ConversationDAG {
        // Topological sort for forward propagation
        const sortedNodes = this.topologicalSort(dag);

        const nodeConfidences = new Map<string, number>();

        for (const node of sortedNodes) {
          // Find incoming edges
          const incomingEdges = dag.edges.filter(e => e.to === node.node_id);

          let parentConfidence: number | null = null;
          let edgeType: string = 'response_to'; // Default

          if (incomingEdges.length > 0) {
            // Use the primary parent (first response_to edge, or first edge)
            const primaryEdge = incomingEdges.find(e => e.type === 'response_to') || incomingEdges[0];
            const parent = dag.nodes.find(n => n.node_id === primaryEdge.from);

            if (parent && nodeConfidences.has(parent.node_id)) {
              parentConfidence = nodeConfidences.get(parent.node_id)!;
              edgeType = primaryEdge.type;
            }
          }

          // Extract evidence confidence from node's belief layers
          const evidenceConfidence = this.extractEvidenceConfidence(node);
          const transductionMethod = this.inferTransductionMethod(node);

          // Compute node confidence using Epistemic Calculus
          const nodeConfidence = this.epistemic.computeNodeConfidence(
            evidenceConfidence,
            transductionMethod,
            parentConfidence,
            edgeType as any
          );

          nodeConfidences.set(node.node_id, nodeConfidence);

          // Update node's attribution with computed confidence
          node.attribution.layers.forEach(layer => {
            if (layer.source.startsWith('system:')) {
              layer.confidence = nodeConfidence;
            }
          });
        }

        return dag;
      }
    }

