          const parentConfidence = parent?.attribution.layers[0]?.confidence || 0;
          const decay = confidence / parentConfidence;

          if (!isNaN(decay) && isFinite(decay)) {
            output += `${indent}  └── Decay factor: ${decay.toFixed(3)} (${parentEdge.type})\n`;
