        const filePath = this.getPath(hash);
        try {
          await fs.access(filePath);
          return true;
        } catch {
          return false;
        }
      }

      private getPath(hash: string): string {
        // Use the first 2 characters as a directory to avoid too many files in one directory
        const dir = path.join(this.basePath, hash.substring(0, 2));
        // Ensure the directory exists
        fs.mkdir(dir, { recursive: true });
        return path.join(dir, hash);
      }
