    export class CE_Epidemiology {
      // INVARIANT 1: Canonical Serialization (RFC 8785)
      static canonicalize(obj: any): string {
        // Implementation of RFC 8785 JSON Canonicalization Scheme
        const replacer = (key: string, value: any) => {
          if (value === undefined) return null;
          if (typeof value === 'number') {
            // Remove trailing zeros, preserve integers
            return Number.isInteger(value) ? value : parseFloat(value.toPrecision(15));
          }
          return value;
        };
        return JSON.stringify(obj, Object.keys(obj).sort(), 0);
      }

      // INVARIANT 2: Merkle-Rooted Integrity
      static computeMerkleRoot(nodes: Array<{ id: string; hash: string }>): string {
        if (nodes.length === 0) return this.sha256('');
        if (nodes.length === 1) return nodes[0].hash;

        // Sort deterministically
        const sortedHashes = nodes
          .map(n => n.hash)
          .sort();

        const nextLevel: string[] = [];
        for (let i = 0; i < sortedHashes.length; i += 2) {
          const left = sortedHashes[i];
          const right = (i + 1 < sortedHashes.length) ? sortedHashes[i + 1] : left;
          nextLevel.push(this.sha256(left + right));
        }

        return this.computeMerkleRoot(nextLevel.map((h, i) => ({ id: `lvl${i}`, hash: h })));
      }

