      static computeEpistemicConfidence(
        baseConfidence: number,
        transductionMethod: 'api_direct' | 'ocr_high_res' | 'ocr_low_res' | 'manual',
        parentConfidence: number | null,
        edgeType: 'formalizes' | 'implements' | 'follows' | 'analyzes'
