        const tFactor: Record<string, number> = {
          'api_direct': 1.0,
          'ocr_high_res': 0.85,
          'ocr_low_res': 0.60,
          'manual': 0.50
        };

        // Propagation factors (relationship decay)
        const pFactor: Record<string, number> = {
          'formalizes': 0.98,
          'implements': 0.95,
          'follows': 0.90,
          'analyzes': 0.85
        };

        const t = tFactor[transductionMethod] || 0.85;
        const p = pFactor[edgeType] || 0.90;

        // Core equation: C_node = C_evidence × T_transduction × δ(C_parent)
        let confidence = baseConfidence * t;
        if (parentConfidence !== null) {
          confidence *= (parentConfidence * p);
        }

        return Math.min(1.0, Math.max(0.0, confidence));
      }

