    /**
     * Genesis Console - Visualization and Verification
     */
    export class GenesisConsole {
      constructor(private cas: CAS_Bridge) {}

      async visualizeEnvelope(envelope: CE_Envelope): Promise<Visualization> {
        const nodes = envelope.content.graph_representation.nodes;
        const edges = envelope.content.graph_representation.edges;

        // Build DAG visualization
        const dagVisualization = {
          nodes: nodes.map(node => ({
            id: node.node_id,
            label: node.evidence?.metadata?.title || node.node_id,
            role: node.role,
            confidence: node.attribution.layers[0]?.confidence || 0,
            // Color coding based on confidence
            color: this.getConfidenceColor(node.attribution.layers[0]?.confidence || 0),
            shape: this.getRoleShape(node.role),
            size: this.getNodeSize(node)
          })),
          edges: edges.map(edge => ({
            from: edge.from,
            to: edge.to,
            type: edge.type,
            label: edge.type,
            // Style based on edge type
            dashes: edge.type === 'analyzes',
            width: this.getEdgeWidth(edge.type)
          }))
        };

        // Build confidence heatmap
        const confidenceRanges = {
          high: nodes.filter(n => (n.attribution.layers[0]?.confidence || 0) >= 0.8).length,
          medium: nodes.filter(n => {
            const c = n.attribution.layers[0]?.confidence || 0;
            return c >= 0.6 && c < 0.8;
          }).length,
          low: nodes.filter(n => (n.attribution.layers[0]?.confidence || 0) < 0.6).length
        };

        // Verify integrity
        const integrity = await this.verifyEnvelopeIntegrity(envelope);

        return {
          dag: dagVisualization,
          confidence_heatmap: confidenceRanges,
          integrity,
          timestamp: new Date().toISOString()
        };
      }

      async verifyEnvelopeIntegrity(envelope: CE_Envelope): Promise<IntegrityReport> {
        const report: IntegrityReport = {
          merkle_root_valid: false,
          cas_objects_valid: true,
          double_handshake_passed: true,
          overall: 'unverified'
        };

        // Verify Merkle root
        const nodes = envelope.content.graph_representation.nodes;
        const nodeHashes = nodes.map(node => ({
          id: node.node_id,
          hash: node.evidence?.cas_reference?.cid || ''
        }));

        const computedRoot = CE_Epidemiology.computeMerkleRoot(nodeHashes);
        report.merkle_root_valid = computedRoot === envelope.provenance?.integrity_hash;

        // Verify CAS objects
        for (const node of nodes) {
          const hash = node.evidence?.cas_reference?.cid;
          if (hash) {
            const valid = await this.cas.verify(hash);
            if (!valid) {
              report.cas_objects_valid = false;
              break;
            }
          }
        }

        // Double handshake verification
        for (const node of nodes) {
          const hash = node.evidence?.cas_reference?.cid;
          if (hash && node.evidence?.metadata) {
            const fingerprint = this.computeNodeFingerprint(node);
            const verification = await this.cas.doubleHandshakeVerify(hash, fingerprint);
            if (verification.overall !== 'trusted') {
              report.double_handshake_passed = false;
              break;
            }
          }
        }

        // Overall assessment
        if (report.merkle_root_valid && report.cas_objects_valid && report.double_handshake_passed) {
          report.overall = 'verified';
        } else if (!report.merkle_root_valid) {
          report.overall = 'tampered';
        } else if (!report.cas_objects_valid) {
          report.overall = 'corrupted';
        } else {
          report.overall = 'suspicious';
        }

        return report;
      }

      private getConfidenceColor(confidence: number): string {
        if (confidence >= 0.8) return '#10b981'; // Emerald
        if (confidence >= 0.6) return '#f59e0b'; // Amber
        return '#ef4444'; // Red
      }

      private getRoleShape(role: string): string {
        const shapes: Record<string, string> = {
          user: 'circle',
          assistant: 'square',
          system: 'triangle',
          unknown: 'diamond',
          system_gap: 'ellipse'
        };
        return shapes[role] || 'circle';
      }

      private getNodeSize(node: any): number {
        const confidence = node.attribution.layers[0]?.confidence || 0;
        return 20 + (confidence * 30); // Scale size with confidence
      }

      private getEdgeWidth(edgeType: string): number {
        const widths: Record<string, number> = {
          formalizes: 3,
          implements: 2,
          follows: 2,
          analyzes: 1,
          root: 4
        };
        return widths[edgeType] || 1;
      }

      private computeNodeFingerprint(node: any): string {
        const data = JSON.stringify({
          id: node.node_id,
          role: node.role,
          content_hash: node.evidence?.cas_reference?.cid,
          confidence: node.attribution.layers[0]?.confidence
        });
        return CE_Epidemiology.sha256(data).substring(0, 16);
      }
    }

