    import Ajv from 'ajv';
    import schema from './ce-schema-v1.0.json';

    export class CEValidator {
      private ajv: Ajv;
      private validate: any;

      constructor() {
        this.ajv = new Ajv({ strict: true, allErrors: true });
        this.validate = this.ajv.compile(schema);
      }

      validateEnvelope(envelope: object): {
        valid: boolean;
        errors?: string[];
        warnings?: string[];
      } {
        const valid = this.validate(envelope);

        if (!valid) {
          return {
            valid: false,
            errors: this.validate.errors?.map(e => 
              `${e.instancePath}: ${e.message}`
            )
          };
        }

        // Additional epistemic checks beyond JSON Schema
        const warnings = this.epistemicAudit(envelope);

        return { valid: true, warnings };
      }

      private epistemicAudit(envelope: any): string[] {
        const warnings: string[] = [];

        // Check: High confidence without evidence
        envelope.content.graph_representation.nodes?.forEach((node: CENode) => {
          if (node.attribution.resolution_summary.confidence > 0.9 && 
              (!node.evidence || node.evidence.source_images?.length === 0)) {
            warnings.push(`Node ${node.node_id}: High confidence without evidence`);
          }
        });

        // Check: Conflict not reflected in consensus_state
        envelope.content.graph_representation.nodes?.forEach((node: CENode) => {
          const activeLayers = node.attribution.layers.filter(l => 
            l.state === 'active' || l.state === 'active_override'
          );
          const conflictingRoles = new Set(activeLayers.map(l => l.role));

          if (conflictingRoles.size > 1 && 
              node.attribution.resolution_summary.consensus_state !== 'conflict') {
            warnings.push(`Node ${node.node_id}: Multiple active roles but no conflict state`);
          }
        });

        return warnings;
      }
    }

