    import { CENode } from '@ce/schema';
    import { embed } from './embedding'; // Mock: could be TensorFlow.js or API call

    export class RegenerationClusterer {
      private similarityThreshold: number;

      constructor(similarityThreshold = 0.85) {
        this.similarityThreshold = similarityThreshold;
      }

      async cluster(nodes: CENode[]): Promise<Map<string, CENode[]>> {
        // 1. Group by parent and temporal position
        const candidateGroups = new Map<string, CENode[]>();

        nodes.forEach(node => {
          if (node.role === 'assistant' && node.parent_node) {
            const key = `${node.parent_node}-${Math.floor(node.temporal_position)}`;
            if (!candidateGroups.has(key)) candidateGroups.set(key, []);
            candidateGroups.get(key)!.push(node);
          }
        });

        // 2. Semantic clustering within each candidate group
        const generationGroups = new Map<string, CENode[]>();

        for (const [key, candidates] of candidateGroups) {
          if (candidates.length < 2) continue;

          // Compute embeddings (batch for efficiency)
          const texts = candidates.map(c => c.content || '');
          const embeddings = await embed(texts);

          // Build similarity matrix
          const clusters: CENode[][] = [];
          const assigned = new Set<number>();

          for (let i = 0; i < candidates.length; i++) {
            if (assigned.has(i)) continue;

            const cluster = [candidates[i]];
            assigned.add(i);

            for (let j = i + 1; j < candidates.length; j++) {
              if (assigned.has(j)) continue;

              const similarity = this.cosineSimilarity(embeddings[i], embeddings[j]);
              if (similarity > this.similarityThreshold) {
                cluster.push(candidates[j]);
                assigned.add(j);
              }
            }

            if (cluster.length > 1) {
              // This is a regeneration group
              const groupId = `gen_${candidates[0].parent_node}_${Date.now()}`;
              cluster.forEach((node, idx) => {
                node.generation_group = groupId;
                node.variant_index = idx;
              });
              generationGroups.set(groupId, cluster);
            }
          }
        }

        return generationGroups;
      }

      private cosineSimilarity(a: number[], b: number[]): number {
        const dot = a.reduce((sum, val, i) => sum + val * b[i], 0);
        const normA = Math.sqrt(a.reduce((sum, val) => sum + val * val, 0));
        const normB = Math.sqrt(b.reduce((sum, val) => sum + val * val, 0));
        return dot / (normA * normB);
      }
    }

