    import { BeliefLayer, ConsensusState } from '@ce/schema';

    export class BeliefStateMachine {
      transition(
        currentState: ConsensusState,
        action: 'user_declare' | 'system_propose' | 'user_override' | 'new_evidence',
        existingLayers: BeliefLayer[]
      ): ConsensusState {
        switch (currentState) {
          case 'unresolved':
            if (action === 'user_declare') return 'user_declared';
            if (action === 'system_propose') return 'system_proposed';
            break;

          case 'user_declared':
          case 'system_proposed':
            if (action === 'new_evidence') {
              // Check if new evidence contradicts existing beliefs
              const hasConflict = this.detectConflict(existingLayers);
              return hasConflict ? 'conflict' : 'system_verified';
            }
            if (action === 'user_override') return 'user_override';
            break;

          case 'conflict':
            if (action === 'user_override') return 'user_override';
            if (action === 'new_evidence') {
              // Evidence might resolve conflict
              return this.evaluateConflictResolution(existingLayers);
            }
            break;

          case 'user_override':
            // User override is terminal unless new evidence strongly contradicts
            if (action === 'new_evidence' && this.isStrongContradiction(existingLayers)) {
              return 'irreconcilable_conflict';
            }
            break;
        }

        return currentState; // No state change
      }

      private detectConflict(layers: BeliefLayer[]): boolean {
        const active = layers.filter(l => l.state === 'active' || l.state === 'active_override');
        const roles = new Set(active.map(l => l.role));
        return roles.size > 1;
      }

      // ... additional state transition logic
    }

