interface AnchoringEngine {
      /**
       * Core transduction: Evidence → DAG Node hypotheses
       */
      anchor(
        evidence: EvidenceBlock[], 
        context: CaptureContext
      ): AnchorHypothesis[];

      /**
       * Conflict resolution between competing hypotheses
       */
      resolveConflicts(
        hypotheses: AnchorHypothesis[]
      ): ResolvedAnchors;

      /**
       * DAG construction from resolved anchors
       */
      constructDAG(
        anchors: ResolvedAnchors,
        existingDAG?: ConversationDAG
      ): ConversationDAG;
    }

    /**
     * An anchor hypothesis represents a probabilistic mapping
     * from evidence to temporal position
     */
    interface AnchorHypothesis {
      evidence_id: string;

      // Proposed temporal placement
      temporal_position: number;
      temporal_confidence: number;  // 0.0-1.0

      // Proposed role inference
      proposed_role: CERole;
      role_confidence: number;      // 0.0-1.0

      // Spatial anchoring evidence
      spatial_anchors: {
        scroll_position?: number;    // pixels from top
        visual_landmarks?: string[]; // "avatar_present", "input_field", etc.
        occlusion_state?: 'none' | 'partial' | 'full';
