    export class ConfidencePropagator {
      /**
       * How confidence flows through the DAG
       * Parent uncertainty → Child uncertainty amplification
       */
      propagate(parentConfidence: number, edgeType: string): number {
        const propagationFactors = {
          'response_to': 0.9,      // Direct response: high confidence transfer
          'follows_from': 0.8,     // Continuation: good transfer
          'branch_of': 0.6,        // Alternative: reduced confidence
          'version_of': 0.95,      // Edit: very high transfer
          'analysis_of': 0.7       // Analysis: moderate transfer
        };

        return parentConfidence * (propagationFactors[edgeType] || 0.5);
      }

      /**
       * Conflict propagation through regeneration chains
       */
      propagateConflict(conflictNode: CENode, downstreamNodes: CENode[]): void {
        // If a node has role conflict, downstream nodes inheriting from it
        // should have confidence discounted
        const conflictDiscount = 0.3;

        downstreamNodes.forEach(node => {
          node.attribution.layers.forEach(layer => {
            layer.confidence *= (1 - conflictDiscount);
          });
        });
      }
    }

