    export class DIDResolver {
      private readonly DID_METHODS = {
        'did:key': resolveDidKey,
        'did:web': resolveDidWeb,
        'did:ce': resolveDidCE  // CE-specific DID method
      };

      async resolve(did: string): Promise<DIDDocument> {
        const method = did.split(':')[1];
        const resolver = this.DID_METHODS[method];

        if (!resolver) {
          throw new Error(`Unsupported DID method: ${method}`);
        }

        return resolver(did);
      }

      async attestEnvelope(envelope: CEEnvelope, did: string): Promise<Attestation> {
        const document = await this.resolve(did);
        const privateKey = await this.getPrivateKey(did);

        // Create JWS with detached payload
        const jws = await createJWS({
          protected: {
            alg: 'EdDSA',
            kid: `${did}#key-1`,
            ce_version: '1.0'
          },
          payload: envelope.integrity_hash
        }, privateKey);

        return {
          jws,
          attestation_time: new Date().toISOString(),
          attester: did
        };
      }
    }

