5\. DAG Validation (`DAG.ts`)
-----------------------------

    import { ProtocolViolation } from "../errors/ProtocolViolation";
    import { CENode, CEEdge } from "../model";

    export function validateDAG(nodes: CENode[], edges: CEEdge[]) {
      const map = new Map(nodes.map(n => [n.node_id, n]));

      // Root
      const roots = nodes.filter(n => n.parent_node === null);
      if (roots.length !== 1) {
        throw new ProtocolViolation("DAG must have exactly one root");
      }

      // Cycles
      const visited = new Set<string>();
      const stack = new Set<string>();

      function dfs(id: string) {
        if (stack.has(id)) throw new ProtocolViolation("Cycle detected");
        if (visited.has(id)) return;

        stack.add(id);
        visited.add(id);

        for (const e of edges.filter(e => e.from === id)) {
          dfs(e.to);
        }

        stack.delete(id);
      }

      dfs(roots[0].node_id);

      // Temporal consistency
      for (const e of edges) {
        const a = map.get(e.from)!;
        const b = map.get(e.to)!;
        if (a.temporal_position >= b.temporal_position) {
          throw new ProtocolViolation(`Temporal ordering violation: ${a.node_id} → ${b.node_id}`);
        }
      }

      return true;
    }


