6\. Belief Append-Only Enforcement (`Belief.ts`)
------------------------------------------------

    import { BeliefLayer } from "../model";
    import { ProtocolViolation } from "../errors/ProtocolViolation";

    export function validateBeliefAppend(
      existing: BeliefLayer[],
      incoming: BeliefLayer
    ) {
      if (existing.some(l => l.layer_id === incoming.layer_id)) {
        throw new ProtocolViolation("Belief layers are immutable");
      }

      if (incoming.confidence > 0.7 && !incoming.justification) {
        throw new ProtocolViolation("High-confidence belief requires justification");
      }

      if (
        incoming.source.startsWith("user:") &&
        incoming.state !== "active_override"
      ) {
        throw new ProtocolViolation("User beliefs must be explicit overrides");
      }

      return true;
    }


