7\. Envelope Hash (`CEEngine.ts`)
---------------------------------

    import { canonicalJSON } from "./Canonical";
    import { sha256 } from "./Hashing";
    import { merkleRoot } from "../utils/Merkle";
    import { CEEnvelope } from "../model";

    export async function computeEnvelopeHash(env: CEEnvelope): Promise<Uint8Array> {
      const canonical = canonicalJSON(env);
      const structureHash = await sha256(canonical);

      const evidenceHashes = await Promise.all(
        env.content.evidence_blocks.map(b =>
          sha256(concat(b.raw_bytes, canonicalJSON(b.metadata)))
        )
      );

      const evidenceRoot = await merkleRoot(evidenceHashes);

      return sha256(concat(structureHash, evidenceRoot));
    }


