8\. Cryptographic Attestation (`Crypto.ts`)
-------------------------------------------

    import * as ed from "@noble/ed25519";

    export async function signEnvelopeHash(
      hash: Uint8Array,
      privateKey: Uint8Array
    ): Promise<Uint8Array> {
      return ed.sign(hash, privateKey);
    }

    export async function verifyEnvelopeSignature(
      hash: Uint8Array,
      signature: Uint8Array,
      publicKey: Uint8Array
    ): Promise<boolean> {
      return ed.verify(signature, hash, publicKey);
    }


