    import { validateDAG } from "../src/engine/DAG";
    import { describe, it, expect } from "vitest";

    describe("CE DAG Validation", () => {
      it("accepts valid DAG", () => {
        const nodes = [
          { node_id: "msg_1", parent_node: null, temporal_position: 1 },
          { node_id: "msg_2", parent_node: "msg_1", temporal_position: 2 }
        ];

        const edges = [{ from: "msg_1", to: "msg_2", type: "response_to" }];

        expect(() => validateDAG(nodes as any, edges as any)).not.toThrow();
      });

      it("rejects cycles", () => {
        const nodes = [
          { node_id: "msg_1", parent_node: null, temporal_position: 1 },
          { node_id: "msg_2", parent_node: "msg_1", temporal_position: 2 }
        ];

        const edges = [
          { from: "msg_1", to: "msg_2", type: "response_to" },
          { from: "msg_2", to: "msg_1", type: "response_to" }
        ];

        expect(() => validateDAG(nodes as any, edges as any)).toThrow();
      });
    });


